import type { Drill } from "./types";

// Consultant / senior drills, keyed by module slug — 25 per module.
// Pitched at a consulting partner or principal: C-suite advisory, selling engagements,
// board readouts, unwelcome recommendations, pricing and staffing negotiations,
// firm leadership, and rescuing troubled engagements. Merged into course.ts.
export const CONSULTANT_SENIOR_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-con-senior-01","level":"senior","profession":"consultant","title":"The steering committee opener","scenario":"You open the monthly steering committee after eight weeks of diagnostic work. The headline: the $40M cost target is achievable, but only if the client closes its smallest plant. Your drafted opening walks through progress workstream by workstream before landing that conclusion.","task":"Write the first two sentences of your steering committee opening, conclusion first.","tips":["Sentence one carries the verdict: target achievable, plant closure required.","Workstream progress is appendix material, not an opener.","Executives decide in the first thirty seconds whether to keep listening."],"focus":["structure","impact"],"placeholder":"The $40M target is achievable — but only if you close the Riverside plant."},
    {"id":"lead-con-senior-02","level":"senior","profession":"consultant","title":"The growth-bets email to the CEO","scenario":"Your team finished pressure-testing the client's five growth bets. Three don't survive contact with the market data. Your draft email to the CEO who sponsored all five opens with a paragraph on methodology.","task":"Write a 2-3 sentence email that puts the finding in the first sentence.","tips":["Lead with the result: three of five bets don't clear the bar.","Methodology earns you the right to the finding — but it goes second.","Name when they'll see the full detail, then stop."],"focus":["clarity","structure"],"placeholder":"Three of the five growth bets don't hold up against the market data —"},
    {"id":"lead-con-senior-03","level":"senior","profession":"consultant","title":"The proposal cover email","scenario":"You're sending a $1.8M transformation proposal to a COO you've met twice. Your draft cover email spends four sentences on how much you enjoyed the workshops before saying what you're actually proposing.","task":"Write a 2-3 sentence cover email that leads with what you propose and why now.","tips":["First sentence: the engagement, its outcome, and the price frame.","Warmth can live in the closing line instead of the opening.","A buried proposal reads like a hesitant one."],"focus":["clarity","impact"]},
    {"id":"lead-con-senior-04","level":"senior","profession":"consultant","title":"The blocked milestone ask","scenario":"Your team has waited nine days for access to the client's cost-center data, and the interim readout is now at risk. Only the CFO can unblock it. Your draft message rehearses everything your team tried before asking.","task":"Write a message to the CFO that puts the ask and the deadline in sentence one.","tips":["Lead with what you need, from whom, by when.","One sentence on consequence: the readout date slips without it.","What you already tried is proof of diligence — keep it to a clause."],"focus":["clarity","impact"],"placeholder":"I need your help unblocking cost-center data access by Friday —"},
    {"id":"lead-con-senior-05","level":"senior","profession":"consultant","title":"The board pre-read first line","scenario":"The board pre-read for Thursday summarizes your market study. Directors will read one page, maybe. Your current first line: 'This document summarizes the findings of the market assessment conducted between March and May.'","task":"Rewrite the first line of the pre-read so it states the single most important conclusion.","tips":["The first line is the one sentence every director will read — spend it on the answer.","Describing the document is meta-commentary; describing the market is the job.","If they read nothing else, what must they know?"],"focus":["impact","concision"],"placeholder":"The core market is shrinking 4% a year; growth must come from adjacencies."},
    {"id":"lead-con-senior-06","level":"senior","profession":"consultant","title":"The synergy warning to the deal team","scenario":"Midway through commercial due diligence you conclude the target's claimed synergies are overstated by roughly a third. The private equity deal team is pricing the bid this week. Your draft update opens with a recap of the work plan.","task":"Write a 2-3 sentence update that leads with the finding and its bid implication.","tips":["Lead with the number: synergies overstated by ~30%.","Tie it immediately to the decision at hand — the bid price.","The work-plan recap belongs in the appendix, if anywhere."],"focus":["impact","precision"],"placeholder":"The synergy case is overstated by roughly a third, which matters for this week's bid —"},
    {"id":"lead-con-senior-07","level":"senior","profession":"consultant","title":"The change-order ask","scenario":"The client added two business units to the scope mid-engagement. You need a $400K fee extension and three more weeks, and the sponsor has to take it to their CFO. Your draft eases in with a history of how scope grew.","task":"Write a 3-4 sentence note that leads with the ask, then justifies it.","tips":["Sentence one: the extension you need and what it covers.","The scope history is the support — two sentences, dated and factual.","Make it easy for the sponsor to forward as-is."],"focus":["clarity","structure"]},
    {"id":"lead-con-senior-08","level":"senior","profession":"consultant","title":"The staffing ask to the practice leader","scenario":"Your engagement needs two more consultants for six weeks or the operating-model workstream slips past the board date. You're emailing the practice leader who controls staffing, and your draft opens with an engagement status tour.","task":"Write a 2-3 sentence internal email that puts the staffing ask first.","tips":["Lead with the ask: two consultants, six weeks, starting when.","One sentence on stakes: the board date is fixed.","Practice leaders triage dozens of asks — make yours instantly legible."],"focus":["clarity","concision"],"placeholder":"I need two consultants for six weeks starting Monday, or the operating-model workstream misses the board date."},
    {"id":"lead-con-senior-09","level":"senior","profession":"consultant","title":"The rescue takeover email","scenario":"You've been brought in to take over an engagement that has burned twelve weeks with little to show. The sponsor is openly frustrated. Your first email as the new lead partner drafts long on empathy before saying what changes.","task":"Write a 3-4 sentence first email that leads with what changes now.","tips":["Lead with the concrete change: new plan, new cadence, first deliverable date.","Acknowledge the frustration in one clause, not one paragraph.","Credibility here comes from specificity, not apology."],"focus":["impact","clarity"],"placeholder":"Here is what changes as of today:"},
    {"id":"lead-con-senior-10","level":"senior","profession":"consultant","title":"The hallway question from the CEO","scenario":"The CEO catches you outside the elevator: 'So — what are you seeing?' You have thirty seconds and a head full of nuance. Your instinct is to start with 'Well, it's still early, and the data has some gaps...'","task":"Say (or write) a 2-3 sentence answer that leads with your strongest current read.","tips":["Give the headline read first, caveats in a clause.","'Still early' is a warm-up, not an answer.","End with when they'll get the full picture."],"focus":["clarity","impact"],"placeholder":"Early read: the pricing problem is bigger than the cost problem."},
    {"id":"lead-con-senior-11","level":"senior","profession":"consultant","title":"The status email that buries the slip","scenario":"Your weekly status email to the sponsor is drafted: four workstreams green, then in paragraph three, the note that the pilot launch will slip two weeks. The slip is the only thing they'll care about.","task":"Rewrite the opening 1-2 sentences so the slip leads.","tips":["Bad news first, in plain words: pilot slips two weeks, here's why in one clause.","Green workstreams are the supporting cast this week.","A slip discovered in paragraph three feels hidden, and hidden reads as worse."],"focus":["clarity","impact"]},
    {"id":"lead-con-senior-12","level":"senior","profession":"consultant","title":"Kill the pilot — say it first","scenario":"The client's much-publicized automation pilot isn't working: adoption is at 9% and unit costs are up. Your recommendation is to stop it. Your draft to the executive sponsor spends two paragraphs honoring the effort before recommending anything.","task":"Write a 2-3 sentence message that puts the recommendation first, then the basis.","tips":["Recommendation in sentence one: stop the pilot.","Two facts of support: adoption, cost. Numbers, not adjectives.","Respect for the effort is one clause, not the opening act."],"focus":["structure","impact"],"placeholder":"Our recommendation is to stop the pilot."},
    {"id":"lead-con-senior-13","level":"senior","profession":"consultant","title":"The promotion memo headline","scenario":"You're writing the promotion case for your engagement manager to the firm's committee. Committee members skim thirty of these. Your draft opens with her tenure history instead of the case for promoting her now.","task":"Write the first two sentences of the memo, leading with the recommendation and the strongest evidence.","tips":["Sentence one: promote, and the single strongest reason.","Tenure and history are context — they go later.","Write the sentence a committee member would quote in the room."],"focus":["structure","impact"]},
    {"id":"lead-con-senior-14","level":"senior","profession":"consultant","title":"The procurement counter","scenario":"Client procurement has asked for a 15% fee reduction as a condition of signing. You've decided to hold price but extend payment terms. Your draft reply narrates your costing logic before stating your position.","task":"Write a 2-3 sentence reply that states your position in sentence one.","tips":["Lead with the position: price holds; here is what moves instead.","Your reasoning is one supporting sentence, not a preamble.","A position stated late sounds negotiable."],"focus":["clarity","impact"],"placeholder":"We're holding the fee at the proposed level — but we can move on payment terms."},
    {"id":"lead-con-senior-15","level":"senior","profession":"consultant","title":"The kickoff opener","scenario":"You're opening the kickoff for a fourteen-week engagement with the client's top twenty leaders in the room. Your drafted opening covers introductions, logistics, and ways of working before saying what the engagement will actually deliver.","task":"Write the first two sentences of your kickoff, leading with the objective and what success looks like.","tips":["Open with the destination: what will be true in fourteen weeks.","Logistics never earn the first sentence.","Give the room one sentence they could repeat to their teams."],"focus":["impact","audience"]},
    {"id":"lead-con-senior-16","level":"senior","profession":"consultant","title":"The diligence verdict call","scenario":"The deal partner calls for your read the night before bids are due. Your verdict: proceed, but the asset is worth 8-10% less than the asking price. You catch yourself opening with the three areas you'd want more time on.","task":"Write the 2-3 sentences you'd say first on that call, verdict leading.","tips":["Verdict first: proceed, at a lower price — then the number.","Open questions are real, but they come after the answer.","The night before bids, hedging first reads as no answer at all."],"focus":["clarity","precision"],"placeholder":"Proceed — but at 8-10% below ask. Here's why:"},
    {"id":"lead-con-senior-17","level":"senior","profession":"consultant","title":"The buried question from the COO","scenario":"The COO sends you a long, winding email about the transformation. Buried in paragraph four is the real question: should they pause hiring in the affected functions? Your draft reply mirrors their email's length and order.","task":"Write a reply that answers the hiring question in sentence one, then addresses the rest briefly.","tips":["Find the decision hiding in the email and answer it first.","Yes or no, then the one condition that matters.","You can honor the rest of their email in a closing sentence."],"focus":["clarity","concision"],"placeholder":"Yes — pause hiring in the two affected functions, with one exception:"},
    {"id":"lead-con-senior-18","level":"senior","profession":"consultant","title":"The escalation to your senior partner","scenario":"The client relationship is deteriorating: the sponsor skipped two steering committees and procurement is asking pointed questions about the renewal. You're emailing the senior partner who owns the account, and your draft opens with engagement highlights.","task":"Write a 2-3 sentence email that leads with the risk and the help you need.","tips":["Lead with the headline: the account is at risk, and here is the signal.","Name the specific help: a partner-to-sponsor call this week.","Highlights can wait for a quarter that isn't on fire."],"focus":["clarity","impact"]},
    {"id":"lead-con-senior-19","level":"senior","profession":"consultant","title":"The workshop readout","scenario":"Yesterday's executive workshop produced three real decisions: consolidate two regions, fund the data platform, delay the ERP upgrade. Your readout email drafts open with attendance, agenda, and 'productive discussion.'","task":"Write an opening 1-2 sentences that lead with the three decisions.","tips":["Decisions are the product — lead with all three, compressed.","'Productive discussion' is filler; the decisions prove it.","Detail on each decision can follow as three short bullets."],"focus":["structure","concision"],"placeholder":"Yesterday's workshop produced three decisions:"},
    {"id":"lead-con-senior-20","level":"senior","profession":"consultant","title":"The post-pitch follow-up","scenario":"You pitched the CEO and CFO on Tuesday. It went well, and you need a decision before your proposed team gets staffed elsewhere in two weeks. Your draft follow-up opens with thanks and a recap of your credentials.","task":"Write a 2-3 sentence follow-up that leads with the ask and the real deadline.","tips":["Lead with the ask: a decision by a named date, and why the date is real.","The team-availability constraint is a fact, not a pressure tactic — state it plainly.","Gratitude fits in the final sentence."],"focus":["clarity","impact"]},
    {"id":"lead-con-senior-21","level":"senior","profession":"consultant","title":"The engagement-manager swap","scenario":"Your engagement manager is rotating off mid-project for a family reason, and a strong replacement starts Monday. The sponsor hates surprises. Your draft message explains the circumstances at length before naming the change.","task":"Write a 2-3 sentence message that leads with the change and the continuity plan.","tips":["Sentence one: who is leaving, who replaces them, when.","Continuity is the sponsor's real question — answer it in sentence two.","Circumstances get a respectful clause, not a paragraph."],"focus":["clarity","structure"],"placeholder":"Sarah rotates off the engagement Friday; Daniel Ortiz, who led the same workstream at two comparable clients, starts Monday."},
    {"id":"lead-con-senior-22","level":"senior","profession":"consultant","title":"The data-room red flag","scenario":"In diligence you've found the target books channel-partner sales a quarter early — revenue recognition that materially flatters growth. The deal team meets in an hour. Your draft note walks through how you found it before saying what it is.","task":"Write a 2-3 sentence note that leads with the issue and its severity.","tips":["First sentence: what the issue is and that it is material.","Quantify in sentence two: how much growth it flatters.","Discovery narrative is for the appendix."],"focus":["impact","precision"],"placeholder":"Material red flag: the target recognizes channel revenue a quarter early —"},
    {"id":"lead-con-senior-23","level":"senior","profession":"consultant","title":"The practice update at the partner meeting","scenario":"You have four minutes at the firm's partner meeting to update on your practice. The number that matters: revenue is up 22% but the pipeline for next quarter is thin. Your draft starts with a tour of recent engagement wins.","task":"Write the first two sentences of your update, leading with both numbers.","tips":["Lead with the full truth: growth strong, pipeline thin — both in sentence one or two.","Wins are evidence, not the headline.","Partners respect a self-reported risk more than a highlight reel."],"focus":["clarity","precision"]},
    {"id":"lead-con-senior-24","level":"senior","profession":"consultant","title":"Declining the RFP","scenario":"A mid-size client you like has issued an RFP you've decided not to bid: the timeline is unworkable and the budget is half of what the work costs. Your draft decline meanders through appreciation before getting to the decision.","task":"Write a 2-3 sentence decline that states the decision first and keeps the door open.","tips":["Decision in sentence one, with the honest reason in a clause.","Vague declines invite a renegotiation you don't want.","Keep the relationship: name what you would bid on."],"focus":["clarity","concision"],"placeholder":"We've decided not to bid on this RFP —"},
    {"id":"lead-con-senior-25","level":"senior","profession":"consultant","title":"The thirty-second voicemail to the chair","scenario":"The board chair asked you to call before tomorrow's meeting. You get voicemail. She needs one thing: whether your findings support the CEO's expansion plan. They mostly do, with one condition on capital phasing.","task":"Script a voicemail of at most three sentences that answers her question first.","tips":["Answer in sentence one: yes, with one condition.","Name the condition precisely in sentence two.","Close with when you're reachable — then stop talking."],"focus":["concision","clarity"],"placeholder":"Short answer: the findings support the expansion, with one condition on capital phasing."}
  ],
  "start-with-the-audience": [
    {"id":"audience-con-senior-01","level":"senior","profession":"consultant","title":"Regression results for the CEO","scenario":"Your team's driver analysis shows price realization explains most of the margin gap — the technical summary reads 'price/mix contributes 340bps of the 500bps EBITDA variance vs. peers.' You're presenting it to a CEO who thinks in customers and competitors, not basis points.","task":"Rewrite the finding in 1-2 sentences the CEO will act on.","tips":["Translate basis points into money and decisions: what is being given away, to whom.","Lead with the CEO's stake: this is the biggest fixable gap.","Keep the statistics available for the CFO — just not in the headline."],"focus":["audience","clarity"],"placeholder":"Most of the margin gap is pricing you control: discounting is giving away roughly $30M a year."},
    {"id":"audience-con-senior-02","level":"senior","profession":"consultant","title":"Same finding, different executive","scenario":"Your org review found spans of control are too narrow: 40% of managers have three or fewer reports. You've framed it for the CFO as cost. Now you're writing the same finding for the CHRO, who hears 'delayering' as an attack on her people agenda.","task":"Write a 2-3 sentence version of the finding framed for the CHRO's stake.","tips":["Find her win: narrow spans also mean stunted development and slow decisions.","Same fact, different so-what — don't soften the fact itself.","One primary audience per message; resist writing for the CFO here."],"focus":["audience","impact"]},
    {"id":"audience-con-senior-03","level":"senior","profession":"consultant","title":"The town hall explanation","scenario":"The client asked you to explain the operating-model redesign at a frontline town hall. Your steering-committee language — 'moving from a geographic to a functional axis with shared services' — will land as noise or as threat to people who run shifts and serve customers.","task":"Write 2-3 sentences explaining the change in the language of the people in the room.","tips":["Translate the axis change into what changes on a Tuesday: who they report to, what stays the same.","Name the fear in the room honestly — vagueness reads as concealment.","No org-design vocabulary survives contact with a town hall."],"focus":["audience","clarity"]},
    {"id":"audience-con-senior-04","level":"senior","profession":"consultant","title":"De-jargoning the board pre-read","scenario":"A draft board pre-read from your team reads: 'We identified 14 value-creation levers across the cost transformation workstreams, with $25M of run-rate EBITDA uplift from wave-one synergy capture.' Two directors run industrial companies; none speak consulting.","task":"Rewrite the sentence in plain business English a director would trust.","tips":["'Levers,' 'workstreams,' 'wave one,' 'capture' — each has a plain replacement.","Directors trust concrete verbs: cut, renegotiate, consolidate.","Jargon signals the deck was written for consultants, not for them."],"focus":["audience","concision"],"placeholder":"We found 14 ways to cut cost; the first round is worth about $25M a year, starting with..."},
    {"id":"audience-con-senior-05","level":"senior","profession":"consultant","title":"The skeptical plant manager","scenario":"You're presenting the throughput analysis at a plant whose manager has run it for nineteen years and has watched three consulting teams come and go. Your slides open with your benchmarking methodology. He cares whether you understand his line.","task":"Write the 2-3 sentences you'd open with to earn his attention.","tips":["Open with what you observed on his floor, specifically — prove you looked.","Position the benchmark as a question for him, not a verdict on him.","Respect is altitude calibration: talk shift-level, not slide-level."],"focus":["audience","clarity"]},
    {"id":"audience-con-senior-06","level":"senior","profession":"consultant","title":"Pitching the consultant-skeptic founder","scenario":"A founder-CEO agreed to meet but opened with 'I've never seen a consulting deck change anything.' Your standard pitch leads with the firm's credentials and framework. That's precisely what he distrusts.","task":"Write your first 2-3 sentences of the meeting, built for this listener.","tips":["Start from his company's specific problem, stated better than he's heard it stated.","Drop the credentials; competence shown beats competence claimed.","Tell him what would make him right to be skeptical — and what's different here."],"focus":["audience","impact"]},
    {"id":"audience-con-senior-07","level":"senior","profession":"consultant","title":"Writing for procurement","scenario":"Your proposal's executive summary sings about transformation outcomes. But the next reader is the client's procurement lead, whose scorecard is price, risk, and comparability — and who will summarize you in a table next to two competitors.","task":"Write 2-3 sentences of a proposal section aimed at what procurement actually scores.","tips":["Give procurement clean rows: fixed fee, named deliverables, exit points.","Ambiguity you leave becomes a risk discount they apply.","Outcome language belongs in the sponsor's section, not this one."],"focus":["audience","precision"]},
    {"id":"audience-con-senior-08","level":"senior","profession":"consultant","title":"Briefing the brand-new analyst","scenario":"A first-week analyst joins your engagement tomorrow. Your instinct is to forward the latest steering deck, which assumes knowledge of 'the Phase 1 findings,' 'the Horizon initiative,' and 'the situation with the CFO.' None of it will parse.","task":"Write a 3-4 sentence orientation note that assumes zero context.","tips":["Spell out every piece of shorthand you'd normally lean on.","Give them the political map in one careful sentence — it's context, and they need it.","The curse of knowledge is strongest about your own engagement."],"focus":["audience","clarity"],"placeholder":"Here's the engagement in four sentences. The client is..."},
    {"id":"audience-con-senior-09","level":"senior","profession":"consultant","title":"The union briefing","scenario":"The operations study you led touches staffing levels, and the client asked you to brief two union representatives. Your efficiency framing — 'labor productivity is 18% below benchmark' — will be heard as 'you're coming for jobs.' They want the truth, stated respectfully, with what happens next.","task":"Write 2-3 sentences that state the finding honestly in terms the representatives can work with.","tips":["Say what the study found and what it did not decide — the line matters here.","Benchmark language dehumanizes; describe the work and the gap concretely.","Name the process and their role in it: audiences listen for their own agency."],"focus":["audience","clarity"]},
    {"id":"audience-con-senior-10","level":"senior","profession":"consultant","title":"Benchmarks for clinical chiefs","scenario":"Your hospital-client work shows OR utilization at 61% against a 75% peer benchmark. You're presenting to surgeon department chiefs who bristle at being managed by spreadsheet and care about patients and block time.","task":"Write 1-2 sentences presenting the finding in terms the chiefs care about.","tips":["Translate utilization into their currency: cases, wait times, block access.","Lead with the patient consequence, not the percentage.","Invite their diagnosis of the gap — they know where the friction is."],"focus":["audience","impact"],"placeholder":"Empty OR time is costing your departments about 30 cases a week — patients who wait longer while blocks sit unused."},
    {"id":"audience-con-senior-11","level":"senior","profession":"consultant","title":"Speaking in returns","scenario":"You're updating the private equity operating partner on the portfolio company's procurement program. Your draft celebrates process milestones — categories sourced, suppliers consolidated. She thinks in EBITDA, multiple, and exit timeline.","task":"Rewrite the update in 2-3 sentences denominated in what she values.","tips":["Convert milestones to money: run-rate savings, EBITDA impact, effect at exit multiple.","Date the money — in-year vs. run-rate matters to her model.","Process detail is available on request; it is not the update."],"focus":["audience","precision"],"placeholder":"Procurement is now worth $6M run-rate EBITDA — roughly $50M at your exit multiple —"},
    {"id":"audience-con-senior-12","level":"senior","profession":"consultant","title":"The delay, framed for the decision","scenario":"A data problem pushes your analysis back ten days. Your draft note to the sponsor explains ETL issues and vendor delays. What the sponsor actually needs to know: does this move the investment-committee date she's promised her CEO?","task":"Write a 2-3 sentence note framed around her decision date, not your pipeline.","tips":["Lead with the answer to her real question: the committee date holds, or it doesn't.","Your technical troubles get one clause at most.","Offer what you can protect: a preliminary view by the original date, if true."],"focus":["audience","clarity"]},
    {"id":"audience-con-senior-13","level":"senior","profession":"consultant","title":"Writing for the chief of staff","scenario":"Everything reaching this CEO passes through his chief of staff, who kills meandering documents and forwards crisp ones. Your team's update is thorough — six paragraphs. You need it to survive her filter.","task":"Write the 2-3 sentence version built for the person who decides what the CEO sees.","tips":["Her question is triage: does the CEO need this, and what for?","Give her the forwarding line: one sentence she can paste above it.","Serve the gatekeeper honestly and you serve the principal."],"focus":["audience","concision"]},
    {"id":"audience-con-senior-14","level":"senior","profession":"consultant","title":"Tech program, audit committee","scenario":"You assessed the client's ERP program and must brief the audit committee. Your findings are full of architecture and integration language. The committee's frame is fiduciary: what could go wrong, how big, who is accountable.","task":"Write 2-3 sentences translating the program's status into risk language the committee owns.","tips":["Their altitude is exposure and control, not architecture.","Quantify the downside scenario in money and time.","Name what management has agreed to do — committees think in accountabilities."],"focus":["audience","structure"],"placeholder":"The program carries two material risks the committee should track:"},
    {"id":"audience-con-senior-15","level":"senior","profession":"consultant","title":"The exec who loses headcount","scenario":"Your recommendation consolidates customer service under one leader — and the regional president you're meeting tomorrow loses 200 people from his organization. The steering-committee framing ('captures $9M through consolidation') will start a war.","task":"Write 2-3 sentences presenting the recommendation to him, honestly, in terms of his position.","tips":["Don't disguise the loss — he can count; name it and move to what he gains or keeps.","Find his genuine stake: service quality in his region, a cleaner P&L, a role in the design.","Respect is telling him before the room hears it."],"focus":["audience","impact"]},
    {"id":"audience-con-senior-16","level":"senior","profession":"consultant","title":"Explaining the client to your own team","scenario":"Your team is frustrated: the sponsor rewrote their deck twice and canceled a readout. They see caprice. You know the sponsor just lost a peer's support and is exposed internally. The team needs enough context to work well, said carefully.","task":"Write 2-3 sentences to your team that explain the behavior without breaching confidences.","tips":["Give the team the why at the altitude they need — pressure exists, without the palace intrigue.","Convert it to guidance: what changes about how we work this week.","Protecting the client's dignity in front of your team is part of the job."],"focus":["audience","clarity"]},
    {"id":"audience-con-senior-17","level":"senior","profession":"consultant","title":"The general counsel reader","scenario":"Your market-entry work touches a licensing question, and the client's general counsel is now on the distribution list. Your draft says the regulatory path is 'basically a formality.' To a GC, breezy certainty about regulation is a red flag — and a liability.","task":"Rewrite the sentence for a reader whose job is what could go wrong.","tips":["Replace breeziness with calibrated language: what is standard, what needs confirmation, by whom.","Show your homework in one clause — the GC reads for whether you did it.","Precision about uncertainty builds more trust than confidence does."],"focus":["audience","precision"]},
    {"id":"audience-con-senior-18","level":"senior","profession":"consultant","title":"Sixty slides to one page","scenario":"The CEO told your sponsor: 'I'm not reading a sixty-slide deck. One page.' The deck is genuinely good — six months of supply-chain work. Now you must choose the altitude: what does a CEO need to decide, and what is detail she pays you to have handled?","task":"Write the first 3-4 sentences of the one-pager.","tips":["Start from her decisions, not your analyses — the page answers 'what do I do?'","Every sentence must survive the test: would the CEO act differently without it?","The sixty slides become your confidence, not her reading."],"focus":["audience","concision"],"placeholder":"You have three decisions to make, and the analysis supports a clear answer on each."},
    {"id":"audience-con-senior-19","level":"senior","profession":"consultant","title":"The conference-panel translation","scenario":"You're on an industry panel explaining your specialty — network optimization in distribution — to a general business audience. Your usual client language ('node rationalization, service-level trade-offs') will lose the room in one sentence.","task":"Write 2-3 sentences explaining what you do and why it matters, for a smart non-specialist.","tips":["Anchor in something everyone knows: packages, warehouses, delivery promises.","One vivid concrete example beats any definition.","Test: could a listener retell it at dinner?"],"focus":["audience","clarity"]},
    {"id":"audience-con-senior-20","level":"senior","profession":"consultant","title":"Beyond the HQ frame","scenario":"You're presenting the growth strategy to the client's country leaders in Southeast Asia. The deck was written at headquarters and reads that way: 'emerging markets' as a line item, examples all from the home market. The room notices this immediately.","task":"Rewrite the 2-3 opening sentences so the regional leaders hear their market treated as primary.","tips":["Open inside their market: their customers, their competitors, their constraint.","'Emerging markets' flattens; name the country and its specific opportunity.","Ask yourself whose examples carry the argument — then swap them."],"focus":["audience","impact"]},
    {"id":"audience-con-senior-21","level":"senior","profession":"consultant","title":"The team that fears the study","scenario":"You need three days of interviews with the client's planning team — the same team whose function your study might restructure. They know it. A breezy scheduling email will get you guarded, useless interviews.","task":"Write a 3-4 sentence interview invitation that addresses what they're actually worried about.","tips":["Acknowledge the elephant plainly: the study looks at how the function is organized.","Say truthfully what the interviews are for and who sees what.","People give real answers to people who level with them."],"focus":["audience","clarity"]},
    {"id":"audience-con-senior-22","level":"senior","profession":"consultant","title":"The script for investor relations","scenario":"The client will reference your cost program on the earnings call, and the IR chief asked for language. Your internal framing — '20% SG&A reduction program' — would invite analyst questions the CFO isn't ready to answer and spook employees who will read the transcript.","task":"Write 1-2 sentences of call-ready language that is accurate for analysts and safe for employees.","tips":["Two audiences hear every earnings call — write for both deliberately.","Concrete but bounded: committed scope, no numbers you can't defend quarterly.","Check each phrase: what question does it invite?"],"focus":["audience","precision"]},
    {"id":"audience-con-senior-23","level":"senior","profession":"consultant","title":"One memo, five executives","scenario":"Your steering-committee memo goes to the CEO, CFO, COO, CHRO, and general counsel. Your draft tries to speak to all five stakes at once and ends up mush. The decision on the table — approve the reorganization design — belongs to the CEO.","task":"Write the memo's opening 2-3 sentences aimed at one primary reader, chosen deliberately.","tips":["Pick the decision-owner as your primary audience; the rest are readers, not targets.","Others' concerns get addressed inside the argument, not in the framing.","A memo for everyone persuades no one."],"focus":["audience","structure"],"placeholder":"This memo asks you to approve the reorganization design at Thursday's meeting."},
    {"id":"audience-con-senior-24","level":"senior","profession":"consultant","title":"The family-owner conversation","scenario":"Your succession-planning work is for a family-owned manufacturer whose 71-year-old founder-chairman measures everything against what his father built. Your draft opens with governance best practices and IRR. His frame is stewardship and the firm outliving him.","task":"Write the 2-3 sentences you'd open with in his office.","tips":["Speak to continuity and legacy first; governance mechanics serve that story.","His resistance isn't ignorance of best practice — it's fear of losing what the firm means.","Use his language: the company's name, his father's shop, the next forty years."],"focus":["audience","impact"]},
    {"id":"audience-con-senior-25","level":"senior","profession":"consultant","title":"Scope boundary, framed as their win","scenario":"The sponsor keeps adding 'quick questions' that are really new workstreams. You need to hold the boundary. Your draft says 'this is out of scope per the SOW' — contractually true, relationally expensive. Reframe it around what the sponsor cares about: her board date.","task":"Write a 2-3 sentence response that holds the line in terms of her interests.","tips":["The boundary protects her deliverable — say that, not the contract clause.","Offer the legitimate path: phase two, a separate letter, a swap.","'Per the SOW' wins the point and loses the client."],"focus":["audience","clarity"],"placeholder":"We can take that on — but not without moving your board readout. Here's the trade:"}
  ],
  "structure-that-carries": [
    {"id":"structure-con-senior-01","level":"senior","profession":"consultant","title":"One governing idea for the readout","scenario":"Your final readout has forty slides across five workstreams. When the sponsor asks 'what's the one thing?', your team can't answer in a sentence. You need a single governing idea that the whole deck ladders up to.","task":"Write the one-sentence governing idea, then the three supporting buckets beneath it.","tips":["The governing idea is the answer to 'what should we do?', not 'what did you study?'","Force everything into three buckets — a fourth usually means two overlap.","If a slide doesn't support the governing idea, it's an appendix."],"focus":["structure","clarity"],"placeholder":"You can hit the target by fixing pricing, consolidating operations, and exiting two markets — in that order."},
    {"id":"structure-con-senior-02","level":"senior","profession":"consultant","title":"SCQA for the proposal","scenario":"Your transformation proposal opens by listing your team's qualifications. The COO reading it has no context for why the situation is urgent now. You want to open with Situation-Complication-Question-Answer instead.","task":"Draft the SCQA opening: one sentence each for situation, complication, question, answer.","tips":["Situation is the stable truth they already accept; complication is what broke it.","The question should feel inevitable by the time you pose it.","Your answer is the engagement — stated as a claim, not a menu."],"focus":["structure","impact"]},
    {"id":"structure-con-senior-03","level":"senior","profession":"consultant","title":"PREP for the board question","scenario":"A director asks whether the recommended market exit is reversible. You know the answer is 'mostly no' with nuance. Your instinct is to start with the nuance and never quite land the point. Use Point-Reason-Example-Point.","task":"Answer the director's question using PREP, in 4-5 sentences.","tips":["Open with the point: largely irreversible, and here's the honest exception.","One reason, one concrete example — resist listing three of each.","Close by restating the point so the room remembers your answer, not your caveats."],"focus":["structure","clarity"],"placeholder":"Largely irreversible — once you release the distribution rights, buying back in takes years."},
    {"id":"structure-con-senior-04","level":"senior","profession":"consultant","title":"Grouping the messy findings list","scenario":"Your team's diagnostic produced eleven findings in the order they were discovered: a pricing issue, then an IT gap, then a pricing issue again, then a governance problem, then IT. The sponsor can't hold eleven items. You need to group them.","task":"Rewrite the eleven-item jumble as three named themes with the findings sorted under each.","tips":["Name each theme by its business meaning, not by function ('Money left on the table', not 'Pricing').","Order themes by size of prize, not by discovery order.","MECE-check: every finding lands in exactly one theme."],"focus":["structure","concision"]},
    {"id":"structure-con-senior-05","level":"senior","profession":"consultant","title":"The pyramid for the CEO memo","scenario":"Your recommendation memo to the CEO argues for closing the smallest plant. Your draft is chronological: how you analyzed, what you found, then the conclusion. A pyramid puts the conclusion on top and the arguments below.","task":"Write the top of the pyramid — the recommendation — and the three arguments that directly support it.","tips":["Answer first; the reader should be able to stop after sentence one and know your view.","Each argument must independently push toward the recommendation.","Data and analysis live under the arguments, not above them."],"focus":["structure","impact"]},
    {"id":"structure-con-senior-06","level":"senior","profession":"consultant","title":"The three-part verbal update","scenario":"The steering committee asks for a five-minute verbal update. Without structure you'll ramble through workstreams. You want a spine the room can follow: where we are, what we found, what we need from you.","task":"Write the three signposted sentences that open each part of your update.","tips":["Announce the structure up front so the room knows what's coming.","'What we need from you' is the payload — don't let it get buried in the middle.","Three parts is the ceiling for a verbal update people can retain."],"focus":["structure","clarity"],"placeholder":"Three things: where we are, the one finding that changes the plan, and one decision we need today."},
    {"id":"structure-con-senior-07","level":"senior","profession":"consultant","title":"The engagement letter that wanders","scenario":"Your draft engagement letter mixes objectives, deliverables, timeline, and fees in a single dense narrative. The client's legal and procurement teams both need to find their piece fast. Structure it so each reader lands where they need to.","task":"Outline the letter as four clearly-labeled sections and write the one-sentence purpose of each.","tips":["Headings are a service to the reader — let each stakeholder skip to their part.","Objectives before deliverables before timeline before fees — that's the logical dependency.","One idea per section; don't smuggle fees into the objectives."],"focus":["structure","concision"]},
    {"id":"structure-con-senior-08","level":"senior","profession":"consultant","title":"SCQA to justify the pivot","scenario":"Eight weeks in, the evidence says the original hypothesis is wrong — the growth problem is really a retention problem. You must tell the sponsor the engagement should pivot. Frame it so the pivot feels earned, not like failure.","task":"Write an SCQA that leads the sponsor to the pivot as the obvious conclusion.","tips":["Situation: what you both believed at kickoff. Complication: what the data revealed.","Make the question the sponsor's own: given this, where should the work go?","The answer — pivot to retention — should feel like their idea by the end."],"focus":["structure","impact"]},
    {"id":"structure-con-senior-09","level":"senior","profession":"consultant","title":"The recommendation with three options","scenario":"You're presenting three strategic options to the board. Your draft describes each option in equal detail with no through-line, so the board can't see how they relate. Give the section a governing logic.","task":"Write the governing sentence that frames all three options, then a one-line spine for each.","tips":["Frame the options along one axis — ambition, risk, or speed — so they're comparable.","Order them so the recommended one is the natural resting point.","A board wants a map, not three separate essays."],"focus":["structure","clarity"],"placeholder":"Three paths, from lowest-risk to highest-return:"},
    {"id":"structure-con-senior-10","level":"senior","profession":"consultant","title":"The status email spine","scenario":"Your weekly status emails have become a wall of undifferentiated updates and the sponsor has stopped reading them. You want a fixed three-part spine every week: on track, watch, decisions needed.","task":"Write the three headers and one example line under each for this week.","tips":["A repeating spine trains the reader where to look each week.","'Decisions needed' goes first if anything is urgent; otherwise last.","Keep 'on track' to a line — green items don't earn detail."],"focus":["structure","concision"]},
    {"id":"structure-con-senior-11","level":"senior","profession":"consultant","title":"Structuring the diligence report","scenario":"Your commercial due diligence report runs eighty pages and the deal partner will read the first two. Your draft opens with market context. He needs the investment thesis assessment on top, everything else laddering below.","task":"Write the report's one-paragraph top: the verdict and the three pillars that support or threaten it.","tips":["The deal partner's question is 'do we buy, and at what price?' — answer it in the first paragraph.","Three pillars: is the market real, is the position defensible, are the numbers clean.","Market context is support for a pillar, not the opening act."],"focus":["structure","impact"]},
    {"id":"structure-con-senior-12","level":"senior","profession":"consultant","title":"The kickoff agenda with a logic","scenario":"Your kickoff agenda is a flat list of eight topics in no particular order. The client leaders in the room will judge whether you have a coherent plan. Group the agenda so it tells a story.","task":"Reorganize the eight topics into three phases with a one-line rationale for the sequence.","tips":["The agenda should read as a journey: understand, then decide, then commit.","Group related items; a flat list signals no prioritization.","Name each phase so the room can see the arc."],"focus":["structure","clarity"]},
    {"id":"structure-con-senior-13","level":"senior","profession":"consultant","title":"The MECE cost breakdown","scenario":"Your cost-reduction deck lists savings by initiative, but two initiatives double-count the same $3M and one category is missing entirely. The CFO will catch it in thirty seconds. You need a clean, mutually-exclusive breakdown.","task":"Restructure the savings into a MECE breakdown and write the top-line total with its three components.","tips":["Mutually exclusive: no dollar counted twice. Collectively exhaustive: no cost bucket missing.","Choose one cut — by function, by lever, or by timing — and hold it.","The CFO trusts the recommendation only if the arithmetic is airtight."],"focus":["structure","precision"],"placeholder":"$40M total, cleanly split: $22M procurement, $12M footprint, $6M SG&A — no overlap."},
    {"id":"structure-con-senior-14","level":"senior","profession":"consultant","title":"The client's rambling problem, structured back","scenario":"The CEO spends ten minutes describing everything wrong with the business, jumping between symptoms. Before you can help, you need to reflect it back as a structured problem. Show him you heard a shape, not a list.","task":"Write the 3-4 sentence reflection that organizes his concerns into a governing problem and its parts.","tips":["Name the one underlying problem beneath his symptoms.","Group his complaints under two or three causes — this is your first proof of value.","Reflecting structure back builds more trust than sympathy does."],"focus":["structure","audience"]},
    {"id":"structure-con-senior-15","level":"senior","profession":"consultant","title":"The board narrative arc","scenario":"Your board presentation has good content but no arc — it's a sequence of analyses. Directors will disengage. You want a narrative spine: here's where you are, here's the fork, here's the path we recommend.","task":"Write the three transition sentences that carry the board from current state to the fork to the recommended path.","tips":["Transitions are the connective tissue — they tell the board why the next slide follows.","The fork is the emotional center: make the choice feel real before you resolve it.","End on the path, stated as a decision the board can approve."],"focus":["structure","impact"]},
    {"id":"structure-con-senior-16","level":"senior","profession":"consultant","title":"Answering 'why should we believe you' with structure","scenario":"A skeptical CFO asks how confident you are in the $40M number. You have three independent sources of evidence but tend to dump them randomly. Structure the answer so the confidence builds.","task":"Answer using a governing claim plus three lines of evidence, in 4-5 sentences.","tips":["Lead with your confidence level as a claim, then support it three ways.","Order evidence from strongest to weakest, not by how you found it.","Three independent lines of evidence beat one restated three ways."],"focus":["structure","precision"],"placeholder":"High confidence — the number holds up three independent ways:"},
    {"id":"structure-con-senior-17","level":"senior","profession":"consultant","title":"The one-pager pyramid","scenario":"The chairman wants your entire market-entry recommendation on one page. Your draft is a flowing essay. A one-pager works only as a strict pyramid: recommendation, then three reasons, then a line of proof under each.","task":"Write the one-pager as a pyramid: recommendation sentence, three reason headers, one proof line each.","tips":["The visual structure should let him grasp the whole argument in fifteen seconds.","Each reason is a full-sentence claim, not a topic label.","If the proof line doesn't fit in one sentence, the reason isn't sharp enough yet."],"focus":["structure","concision"]},
    {"id":"structure-con-senior-18","level":"senior","profession":"consultant","title":"Sequencing the change story","scenario":"You're presenting a three-year transformation roadmap. Your draft lists thirty initiatives by workstream, which hides the sequence and the dependencies. Executives need to see waves, not a catalog.","task":"Restructure the roadmap into three waves and write the one-sentence theme of each wave.","tips":["Waves should reflect dependency and capacity, not just calendar quarters.","Each wave needs a theme the CEO can name to the organization.","Thirty initiatives are unmanageable; three waves are a plan."],"focus":["structure","clarity"],"placeholder":"Three waves: stabilize the core, then modernize operations, then expand — each unlocking the next."},
    {"id":"structure-con-senior-19","level":"senior","profession":"consultant","title":"The interview synthesis","scenario":"You've done twenty executive interviews and your notes are a swamp of quotes. The sponsor wants the synthesis tomorrow. You need to structure two hundred data points into a handful of themes with tension surfaced.","task":"Write the governing insight from the interviews plus three themes, one sentence each.","tips":["The synthesis is your judgment about what the quotes mean, not a quote catalog.","Surface the disagreement: where do the executives split, and why does it matter.","Three themes with tension beat ten themes that all agree."],"focus":["structure","precision"]},
    {"id":"structure-con-senior-20","level":"senior","profession":"consultant","title":"The pricing-negotiation structure","scenario":"You're going into a fee negotiation with procurement and tend to argue point by point as they raise objections, which puts you on the back foot. You want to open with a structured frame that anchors the whole conversation.","task":"Write the three-part opening frame: value delivered, what the fee covers, where you can flex.","tips":["Anchor on value before price — structure the conversation around outcomes.","Name up front what's fixed and what's flexible so the haggling stays in bounds.","A frame you set is a frame you control."],"focus":["structure","impact"]},
    {"id":"structure-con-senior-21","level":"senior","profession":"consultant","title":"The rescue plan on one slide","scenario":"The troubled engagement needs a recovery plan you can present to the frustrated sponsor in two minutes. Your draft is a dense project schedule. He needs a clear structure: what went wrong, what changes, what he sees by when.","task":"Write the three-part recovery structure with one line under each.","tips":["Past-present-future: acknowledge, reset, commit — in that order.","The 'what he sees by when' part is the trust rebuilder; make it concrete.","A project schedule is not a recovery story."],"focus":["structure","clarity"],"placeholder":"Three things: what went wrong, what changes today, and the deliverable you'll see Friday."},
    {"id":"structure-con-senior-22","level":"senior","profession":"consultant","title":"The firm all-hands update","scenario":"You're updating your practice at the firm all-hands. Your draft lists client wins, hires, and losses in a random order. The partners want to see the health of the practice at a glance: growth, capability, risk.","task":"Restructure the update under three headers — growth, capability, risk — with one line each.","tips":["A fixed three-part frame lets partners assess the practice fast.","Put risk last but don't omit it — honesty about risk is credibility.","Wins and hires are evidence under 'growth' and 'capability', not standalone lists."],"focus":["structure","concision"]},
    {"id":"structure-con-senior-23","level":"senior","profession":"consultant","title":"The SCQA for the unwelcome finding","scenario":"You must tell the executive who championed a program that it isn't working. A blunt open will trigger defensiveness. SCQA lets you build the shared ground before the hard turn: here's what we hoped, here's what happened, here's the question, here's the honest answer.","task":"Write the SCQA, ending on the recommendation to stop or fix the program.","tips":["Situation: the shared goal you both still hold. Complication: the evidence, stated neutrally.","Let the question expose the gap so the answer feels forced by facts, not by you.","The structure carries the bad news so you don't have to blurt it."],"focus":["structure","impact"]},
    {"id":"structure-con-senior-24","level":"senior","profession":"consultant","title":"Structuring the staffing case","scenario":"You're asking the practice leader for two more consultants and a longer runway. Your draft mixes the ask, the justification, and the fallback into one paragraph. Structure it so the decision is easy.","task":"Write the ask in three labeled parts: what you need, why, and the fallback if you can't have it.","tips":["Separate the ask from its justification from the contingency — the reader triages faster.","The fallback shows you've thought past a 'no' and earns the 'yes'.","One paragraph forces the reader to do the sorting you should have done."],"focus":["structure","clarity"]},
    {"id":"structure-con-senior-25","level":"senior","profession":"consultant","title":"The closing-slide logic","scenario":"Your final board deck ends with a slide titled 'Next Steps' that lists twelve actions with no owner or sequence. The board can't approve a jumble. Structure it into what they decide today, what happens next, and who owns it.","task":"Restructure the twelve actions into three groups — decide now, do next, owners — with a line each.","tips":["Separate what the board decides from what management executes.","Every action needs an owner and a date or it isn't a next step, it's a wish.","The closing structure determines what actually happens after the room clears."],"focus":["structure","precision"],"placeholder":"Three groups: two decisions for the board today, four actions this quarter, and a named owner on each."}
  ],
  "cut-to-the-bone": [
    {"id":"concise-con-senior-01","level":"senior","profession":"consultant","title":"Halve the executive summary","scenario":"Your executive summary runs six paragraphs of throat-clearing before the recommendation. The CEO reads exactly one paragraph. You need to cut it to a third without losing a single load-bearing fact.","task":"Rewrite the six-paragraph summary as two tight paragraphs.","tips":["Delete every sentence that describes what the document will do rather than doing it.","Merge the three 'context' paragraphs into one; context earns one paragraph, not four.","If a sentence survives without changing the meaning, it wasn't load-bearing."],"focus":["concision","clarity"]},
    {"id":"concise-con-senior-02","level":"senior","profession":"consultant","title":"Kill the hedges","scenario":"Your recommendation to the board is buried under qualifiers: 'we would tentatively suggest that it may be worth considering whether...'. The hedging makes a firm recommendation sound like a shrug. Strip it.","task":"Rewrite the hedged recommendation as one direct sentence.","tips":["'We recommend X.' — that's the whole grammar of a recommendation.","Each hedge you keep invites the board to discount your confidence.","Real uncertainty gets one honest caveat, not five reflexive ones."],"focus":["concision","impact"],"placeholder":"We recommend exiting the consumer division within twelve months."},
    {"id":"concise-con-senior-03","level":"senior","profession":"consultant","title":"Denominalize the finding","scenario":"Your slide reads: 'The implementation of a rationalization of the supplier base would result in a reduction of procurement costs.' Buried under nominalizations is a simple, strong claim. Free the verbs.","task":"Rewrite the sentence using strong verbs and no more than fifteen words.","tips":["'Rationalization,' 'reduction,' 'implementation' — turn each noun back into a verb.","Consultants nominalize to sound rigorous; it reads as evasive.","Who does what to what? Answer that and the sentence writes itself."],"focus":["concision","clarity"],"placeholder":"Cutting the supplier list from 400 to 120 saves roughly $8M a year."},
    {"id":"concise-con-senior-04","level":"senior","profession":"consultant","title":"Cut the meta-commentary","scenario":"Your update email is half commentary about the email: 'I wanted to reach out to let you know that I think it's important to flag that...'. The sponsor's time is being spent on packaging, not content. Cut to the message.","task":"Rewrite the opening so the first words carry information, not throat-clearing.","tips":["'I wanted to reach out to let you know' says nothing — start with the news.","Meta-commentary is the writer clearing their own throat at the reader's expense.","The reader knows you're emailing them; you don't need to announce it."],"focus":["concision","clarity"]},
    {"id":"concise-con-senior-05","level":"senior","profession":"consultant","title":"The redundant pairs","scenario":"Your proposal is full of doubled phrases: 'clear and transparent,' 'each and every,' 'first and foremost,' 'plans and strategies.' They pad the word count and dull the prose. Strip the redundancy.","task":"Rewrite a proposal sentence, removing every redundant pair, and note the pairs you cut.","tips":["If two words mean the same thing, keep the stronger one.","Doubled phrases are a verbal tic, not emphasis.","Lean prose reads as confident; padded prose reads as uncertain."],"focus":["concision","precision"]},
    {"id":"concise-con-senior-06","level":"senior","profession":"consultant","title":"The two-minute answer, cut to thirty seconds","scenario":"In the steering committee you tend to give two-minute answers to yes-or-no questions. The sponsor's eyes glaze. A director asked: 'Are we on budget?' You know the answer is 'yes, with one risk.' Say it in two sentences.","task":"Write the two-sentence answer to 'Are we on budget?'","tips":["Lead with yes or no — the rest is footnote.","One risk, named. Not three, not a tour of the budget.","Brevity in a live answer signals command; length signals anxiety."],"focus":["concision","clarity"],"placeholder":"Yes, on budget — the one risk is the data-migration line, which I'm watching."},
    {"id":"concise-con-senior-07","level":"senior","profession":"consultant","title":"Trim the slide title","scenario":"Your slide title reads: 'Analysis of Potential Opportunities for Margin Improvement Across the Portfolio Suggests Several Areas of Focus.' A slide title should be the takeaway in under ten words. Cut it.","task":"Rewrite the slide title as an assertion in eight words or fewer.","tips":["A title that describes the analysis wastes the most valuable line on the slide.","Make it a claim: what should the reader conclude from this slide?","'Suggests several areas of focus' is a non-answer — name the areas or the number."],"focus":["concision","impact"],"placeholder":"Three products drive 80% of the margin gap."},
    {"id":"concise-con-senior-08","level":"senior","profession":"consultant","title":"The bloated status paragraph","scenario":"Your status update on the pricing workstream is a 120-word paragraph that says, essentially, 'on track, one dependency.' The sponsor scans ten of these. Compress it without dropping the dependency.","task":"Rewrite the 120-word update in under 25 words.","tips":["State status, then the one thing that could change it. Stop.","Most of a status update is reassurance the reader didn't ask for.","The dependency is the only part that requires action — protect it, cut around it."],"focus":["concision","clarity"]},
    {"id":"concise-con-senior-09","level":"senior","profession":"consultant","title":"Cut the qualifying clauses","scenario":"Your key finding is smothered in qualifying clauses: 'Based on the data we were able to gather in the time available, and subject to the caveats outlined in the appendix, it appears that...'. The finding is solid. Say it plainly.","task":"Rewrite the finding as a clean assertion, with at most one genuine caveat.","tips":["Front-loaded qualifiers make a solid finding sound shaky.","Keep the one caveat that would actually change a decision; cut the rest.","'It appears that' — either you found it or you didn't."],"focus":["concision","precision"]},
    {"id":"concise-con-senior-10","level":"senior","profession":"consultant","title":"The overwritten thank-you","scenario":"Your post-engagement note to the client CEO runs four flowery paragraphs of gratitude. It reads as performance, not sincerity. A senior partner's thank-you should be warm and brief.","task":"Rewrite the note as three sentences: specific thanks, one genuine observation, an open door.","tips":["Specific beats effusive — name the one thing you admired about working with them.","Length reads as trying too hard; brevity reads as confidence.","The open door is the point; don't bury it under adjectives."],"focus":["concision","audience"]},
    {"id":"concise-con-senior-11","level":"senior","profession":"consultant","title":"The 40-slide deck at 12 slides","scenario":"Your team built a 40-slide readout. The sponsor gets 20 minutes with the CEO. You need the 12 slides that carry the argument and the discipline to cut 28 good ones. Decide what the spine is.","task":"List the 12 slide titles that survive, and name the argument each one advances.","tips":["Keep only slides that change what the CEO does; cut the ones that merely inform.","Backup is respect for the reader's time, not a graveyard for your effort.","If two slides make the same point, one of them is backup."],"focus":["concision","structure"]},
    {"id":"concise-con-senior-12","level":"senior","profession":"consultant","title":"Trim the email subject and first line","scenario":"Your email to a busy COO has the subject 'Update and some thoughts on next steps following our conversation' and opens with 'Further to our discussion earlier this week, I wanted to circle back...'. Both waste the reader's first three seconds.","task":"Rewrite the subject line and first sentence so both carry the actual news.","tips":["The subject line should let the COO decide in two seconds whether to open now.","'Further to our discussion, I wanted to circle back' is pure runway — delete it.","First words are the most valuable real estate in the email."],"focus":["concision","impact"],"placeholder":"Subject: Decision needed by Friday — pilot go/no-go"},
    {"id":"concise-con-senior-13","level":"senior","profession":"consultant","title":"The circular executive paragraph","scenario":"A paragraph in your board pre-read circles: it states a point, restates it differently, then concludes by restating it again. Directors will feel padded. Cut it to the one version that's clearest.","task":"Rewrite the circular paragraph as one sentence that says it once, well.","tips":["Saying it three ways doesn't triple the emphasis; it triples the reader's suspicion.","Pick the sharpest of the three versions and delete the other two.","Repetition for its own sake reads as not trusting your own point."],"focus":["concision","clarity"]},
    {"id":"concise-con-senior-14","level":"senior","profession":"consultant","title":"The over-caveated risk slide","scenario":"Your risk slide has fourteen risks, most of them theoretical. The board can't tell which three actually matter. Cut it to the risks that would change a decision.","task":"Reduce the fourteen risks to the three material ones and write each as a single clause.","tips":["A risk that wouldn't change the board's decision isn't a risk worth their attention.","Rank by likelihood times impact, keep the top three.","Fourteen risks reads as either paranoia or a failure to prioritize."],"focus":["concision","precision"],"placeholder":"Three material risks: supplier concentration, the regulatory approval timeline, and key-talent retention."},
    {"id":"concise-con-senior-15","level":"senior","profession":"consultant","title":"Compress the methodology","scenario":"Your report devotes two pages to methodology: sample sizes, interview counts, data sources, analytical approach. The executive reader needs to trust the rigor in three sentences, not audit it in two pages.","task":"Compress the methodology into three sentences that establish credibility.","tips":["The reader wants to know it's rigorous, not to reproduce it.","Lead with the strongest credibility signal — scale, independence, or triangulation.","Detailed methodology belongs in an appendix for the one reader who wants it."],"focus":["concision","precision"]},
    {"id":"concise-con-senior-16","level":"senior","profession":"consultant","title":"The padded proposal objectives","scenario":"Your proposal lists eight objectives, several overlapping and one purely aspirational. The client reads objectives as promises. Cut to the three you'll actually be held to.","task":"Reduce the eight objectives to three sharp, measurable ones.","tips":["Every objective is a promise; don't promise what you can't measure.","Merge overlapping objectives; drop the aspirational one entirely.","Three objectives you'll hit beat eight you'll be judged against."],"focus":["concision","precision"]},
    {"id":"concise-con-senior-17","level":"senior","profession":"consultant","title":"The verbose 'no'","scenario":"You're declining a client's request for a scope addition and your draft cushions it in three paragraphs of context before the 'no,' which reads as evasive. A clean 'no' with a reason is kinder and shorter.","task":"Rewrite the decline in three sentences: the no, the reason, the alternative.","tips":["Bury the 'no' and it reads as unwillingness to say it plainly.","One honest reason beats three paragraphs of cushioning.","The alternative is where your relationship-preserving energy should go."],"focus":["concision","clarity"],"placeholder":"We can't add that without moving the board date — here's the alternative:"},
    {"id":"concise-con-senior-18","level":"senior","profession":"consultant","title":"Trim the interview quote wall","scenario":"Your synthesis slide has eight verbatim quotes to make one point. It's a wall of text no one reads. Pick the one quote that lands and cut the rest.","task":"Choose the single sharpest quote and write the one-line insight it illustrates.","tips":["One vivid quote persuades; eight similar quotes exhaust.","The insight is yours; the quote is evidence — keep the ratio one-to-one.","If you need eight quotes, the point isn't as strong as you think."],"focus":["concision","impact"]},
    {"id":"concise-con-senior-19","level":"senior","profession":"consultant","title":"The over-explained recommendation","scenario":"Your recommendation slide spends four bullets justifying itself before stating what to do. By bullet three the reader has lost the thread. State the recommendation, then support it briefly.","task":"Rewrite so the recommendation is the first line and the justification is one line beneath.","tips":["Recommendation first, justification second — never the reverse.","Four bullets of pre-justification is anxiety, not rigor.","If the recommendation is right, it survives one line of support."],"focus":["concision","structure"]},
    {"id":"concise-con-senior-20","level":"senior","profession":"consultant","title":"The bloated firm bio","scenario":"Your firm's bio in the proposal runs a full page of accolades and history. The client cares about one thing: have you done this specific work before. Cut the page to a paragraph.","task":"Rewrite the firm bio as one paragraph focused on relevant, specific proof.","tips":["Relevance beats prestige — name the two comparable engagements, drop the rest.","Founding year and office count don't win the work.","A page of credentials reads as insecurity; a sharp paragraph reads as confidence."],"focus":["concision","audience"]},
    {"id":"concise-con-senior-21","level":"senior","profession":"consultant","title":"The rambling voicemail","scenario":"You leave the sponsor a voicemail that runs ninety seconds and buries the one ask — a call back before Thursday — in the middle. Voicemail rewards brevity. Cut it.","task":"Script a voicemail of at most three sentences with the ask up front.","tips":["State who, what you need, and by when — in the first sentence.","Rambling voicemails get deleted before the ask arrives.","Say your number slowly at the end and stop."],"focus":["concision","clarity"],"placeholder":"It's Alex — I need ten minutes before Thursday's board call on the pricing decision."},
    {"id":"concise-con-senior-22","level":"senior","profession":"consultant","title":"The over-qualified 'I don't know'","scenario":"Asked a question you can't yet answer, you produce a paragraph of throat-clearing to avoid saying 'I don't know.' It wastes the room's time and reads as evasive. Say it cleanly with a path.","task":"Rewrite the evasive non-answer as a two-sentence honest 'I don't know, and here's how I'll find out.'","tips":["'I don't know yet' is two words of strength when followed by a plan.","The paragraph of hedging is the tell that you're avoiding the admission.","Name when you'll know — that's the part they actually want."],"focus":["concision","impact"],"placeholder":"I don't know yet — I'll have a firm answer by Wednesday after we see the cohort data."},
    {"id":"concise-con-senior-23","level":"senior","profession":"consultant","title":"The dense appendix reference","scenario":"A sentence in your report reads: 'As detailed more fully in the analysis presented in Appendix C, which builds on the framework introduced in Section 2, the data indicates...'. The cross-referencing machinery buries the finding. Cut to the finding.","task":"Rewrite the sentence so the finding leads and the reference shrinks to a parenthetical.","tips":["Readers want the finding, not a tour of your document's architecture.","Move the cross-reference to a parenthetical or a footnote.","Every word spent on navigation is a word not spent on substance."],"focus":["concision","clarity"]},
    {"id":"concise-con-senior-24","level":"senior","profession":"consultant","title":"The overlong partner-meeting update","scenario":"You have four minutes at the partner meeting but your prepared remarks run seven. You must cut three minutes of good material. Decide what the partners actually need from you.","task":"Write the 90-second version: three sentences that carry the whole update.","tips":["Partners need the number and the risk, not the narrative.","Cut every sentence that's context they already have.","Finishing early in a partner meeting is a gift, not a failure."],"focus":["concision","impact"]},
    {"id":"concise-con-senior-25","level":"senior","profession":"consultant","title":"The wordy engagement risk email","scenario":"You're flagging that a client relationship is souring, but your email wraps the warning in so much diplomatic padding that the senior partner might miss it entirely. Cut the padding; keep the diplomacy in the framing, not the length.","task":"Rewrite the email in three sentences: the risk, the evidence, the help needed.","tips":["Diplomacy lives in word choice, not word count.","A warning padded into invisibility isn't diplomatic, it's ineffective.","Give the partner the fact, the signal, and the ask — nothing else."],"focus":["concision","clarity"],"placeholder":"The account is at risk — the sponsor has skipped two steering committees and gone quiet. I need a partner call this week."}
  ],
  "precision-and-evidence": [
    {"id":"precision-con-senior-01","level":"senior","profession":"consultant","title":"Replace 'significant' with a number","scenario":"Your slide claims the cost opportunity is 'significant' and the upside 'substantial.' The CFO doesn't act on adjectives. You have the underlying numbers — put them on the slide.","task":"Rewrite the two vague claims with specific figures and a comparison that gives them scale.","tips":["'Significant' is what you write when you haven't done the arithmetic — do it.","Anchor the number to something: percent of EBITDA, dollars per year, versus peers.","A number the CFO can check is worth ten adjectives she can't."],"focus":["precision","impact"],"placeholder":"The opportunity is $34M a year — roughly 3% of revenue and larger than last year's entire cost program."},
    {"id":"precision-con-senior-02","level":"senior","profession":"consultant","title":"Data to a single insight","scenario":"Your slide shows a dense table of margin by product, region, and channel. The CEO stares at it and asks 'so what?'. Buried in the table is one insight: three products in one region destroy value. Surface it.","task":"Write the one-sentence insight the table proves, and name which cells prove it.","tips":["A table shows data; your job is to state what it means.","The insight is a claim with a direction — up, down, concentrated, at risk.","If the CEO has to find the point in the table, you haven't done your job."],"focus":["precision","clarity"],"placeholder":"Three products in the Southeast region lose money on every unit — everything else is profitable."},
    {"id":"precision-con-senior-03","level":"senior","profession":"consultant","title":"What / So What / Now What","scenario":"Your finding stops at 'What': 'Customer churn rose from 8% to 14% this year.' The sponsor needs the So What (why it matters in money) and the Now What (the action). Complete the chain.","task":"Write the three-part finding: What, So What, Now What, one sentence each.","tips":["'So what' converts the fact into consequence the executive feels.","'Now what' is the recommendation — without it the finding is trivia.","Each step should feel forced by the one before it."],"focus":["precision","structure"],"placeholder":"Churn rose from 8% to 14%. That's $22M of lost annual revenue. We should redirect the retention budget to the two segments driving it."},
    {"id":"precision-con-senior-04","level":"senior","profession":"consultant","title":"Pass the skeptic test","scenario":"You claim the market will grow 12% annually. A skeptical director will ask 'says who, and why should I believe it?'. Your draft asserts the number with no visible basis. Arm the claim.","task":"Rewrite the growth claim so the source and reasoning are visible in the sentence.","tips":["A number without a source is an opinion; with a source it's evidence.","Name the driver, not just the rate — growth of what, driven by what.","Write the sentence so the skeptic's next question is already answered."],"focus":["precision","impact"],"placeholder":"The market grows 12% a year through 2028, driven by the regulatory mandate taking effect in three states — per the IEA's published projections."},
    {"id":"precision-con-senior-05","level":"senior","profession":"consultant","title":"Date the vague timeline","scenario":"Your recommendation says the transformation will pay back 'in the medium term' and deliver savings 'going forward.' The CFO models cash flows quarter by quarter. Give her dates and a curve.","task":"Rewrite the timeline claim with specific dates and the shape of the savings ramp.","tips":["'Medium term' means nothing to a model — give quarters or years.","Savings ramp; say when they start and when they reach run-rate.","Vague timing signals you haven't planned the execution."],"focus":["precision","clarity"],"placeholder":"Savings start in Q3, reach $2M/quarter by year-end, and hit the $18M run-rate by Q2 next year."},
    {"id":"precision-con-senior-06","level":"senior","profession":"consultant","title":"Quantify the qualitative finding","scenario":"Your interview finding reads 'morale is low and people are frustrated with leadership.' It's true but unactionable. You have the survey data behind it. Convert the impression into evidence.","task":"Rewrite the finding with the numbers that make it undeniable.","tips":["'Low morale' is a feeling; a stat is a fact the executive can't wave away.","Pick the number that most connects to a business outcome — attrition, not just sentiment.","Qualitative color plus one hard number is more persuasive than either alone."],"focus":["precision","impact"],"placeholder":"Engagement scores fell 22 points in a year and regrettable attrition doubled to 19% — concentrated in the three teams reporting to the COO."},
    {"id":"precision-con-senior-07","level":"senior","profession":"consultant","title":"The evidence chain for the recommendation","scenario":"You recommend exiting a business line. The board will ask what makes you sure. Your draft asserts it's the right call but doesn't show the three data points that force the conclusion. Build the chain.","task":"Write the recommendation plus the three specific pieces of evidence that lead to it.","tips":["Each piece of evidence should independently point the same way.","Use hard numbers: the line's return on capital, its trend, its strategic fit.","A recommendation is only as strong as the evidence you can name for it."],"focus":["precision","structure"]},
    {"id":"precision-con-senior-08","level":"senior","profession":"consultant","title":"Stress-test your own number","scenario":"Your team's $50M savings estimate rests on an assumption the CFO will probe: that 90% of identified savings actually land. Historically clients capture 60%. Present the number honestly, with the sensitivity.","task":"Write the savings claim with the base case, the realistic case, and the assumption that separates them.","tips":["Show the range, not a single hero number the CFO can puncture.","Name the assumption that drives the spread — capture rate, here.","Presenting your own downside builds more trust than defending a single figure."],"focus":["precision","impact"],"placeholder":"$50M at full capture; $33M at the 60% rate clients typically achieve — the gap is entirely execution discipline."},
    {"id":"precision-con-senior-09","level":"senior","profession":"consultant","title":"Vague benchmark to specific comparator","scenario":"You claim the client is 'behind industry best practice' on procurement. The CPO will ask 'behind whom, on what?'. Replace the vague benchmark with a named, specific comparison.","task":"Rewrite the benchmark claim naming the peer set, the metric, and the gap.","tips":["'Best practice' is a phrase clients have learned to distrust — be specific.","Name the metric and the number: spend under management, savings rate, cycle time.","A gap you can quantify is a gap the client can close."],"focus":["precision","clarity"],"placeholder":"Top-quartile peers put 85% of spend under management; you're at 55% — that 30-point gap is worth about $12M."},
    {"id":"precision-con-senior-10","level":"senior","profession":"consultant","title":"The 'we believe' problem","scenario":"Your report is studded with 'we believe,' 'we feel,' and 'it seems.' To a board, these signal opinion where they want evidence. Replace belief-language with the facts underneath it.","task":"Rewrite three belief-phrased claims as evidence-backed assertions.","tips":["'We believe X' invites 'and I believe otherwise' — state the basis instead.","If you can't replace 'we believe' with evidence, the claim isn't ready.","Reserve 'we believe' for genuine judgment calls, and flag those as such."],"focus":["precision","impact"]},
    {"id":"precision-con-senior-11","level":"senior","profession":"consultant","title":"The chart that overclaims","scenario":"Your chart shows two lines rising together and your title says one causes the other. A director trained in statistics will ask about causation. Tighten the claim to what the data actually supports.","task":"Rewrite the chart's takeaway so it claims exactly what the evidence supports, no more.","tips":["Correlation in a chart is not causation in a claim — say what you know.","If you have a causal argument, state the mechanism, not just the two lines.","Overclaiming once costs you credibility on every claim after."],"focus":["precision","clarity"]},
    {"id":"precision-con-senior-12","level":"senior","profession":"consultant","title":"The sizing that skips a step","scenario":"You size a growth opportunity at $200M but the logic jumps from market size to your number without showing the funnel. The CFO will want to see the assumptions. Make the sizing auditable.","task":"Write the sizing as a short chain: total market, addressable share, realistic capture, resulting number.","tips":["Show every multiplier so the CFO can challenge one without rejecting all.","State each assumption as a number she can pressure-test.","A sized number with a visible chain survives scrutiny; a bare number doesn't."],"focus":["precision","structure"],"placeholder":"$4B market, $800M addressable given our footprint, 25% realistic capture = $200M over five years."},
    {"id":"precision-con-senior-13","level":"senior","profession":"consultant","title":"Vague risk to quantified exposure","scenario":"Your risk register says the ERP program has 'high risk of delay.' The audit committee needs exposure in time and money. Convert the qualitative rating into a quantified scenario.","task":"Rewrite the risk as a specific exposure: probability, delay in months, cost impact.","tips":["'High risk' is a color; the committee governs with numbers.","Give a scenario: if the integration slips, it's X months and $Y.","Quantified risk lets the committee decide whether to act; a rating doesn't."],"focus":["precision","impact"]},
    {"id":"precision-con-senior-14","level":"senior","profession":"consultant","title":"The insight hiding in the average","scenario":"Your slide reports 'average handle time improved 8%.' But the average hides the real story: two sites improved 25% while three got worse. The average misleads. Report the distribution's insight.","task":"Rewrite the finding so it reveals the variation the average conceals.","tips":["Averages hide the action; the spread is where the insight lives.","Name the outliers — the two that improved and the three that regressed.","An executive acts on the variance, not the mean."],"focus":["precision","clarity"],"placeholder":"The 8% average hides a split: two sites improved 25%, three worsened — the story is what those two did differently."},
    {"id":"precision-con-senior-15","level":"senior","profession":"consultant","title":"The unfalsifiable claim","scenario":"Your deck claims the strategy will 'position the company for long-term success.' It can't be wrong, which means it can't be evaluated. Replace it with a claim that could actually be tested.","task":"Rewrite the vague aspiration as a specific, measurable claim about a defined outcome.","tips":["If no evidence could disprove your claim, it's not a claim — it's a mood.","Attach it to a metric and a horizon: what, how much, by when.","Executives fund testable claims, not affirmations."],"focus":["precision","impact"],"placeholder":"This strategy grows EBITDA margin from 12% to 18% within three years by shifting the mix toward services."},
    {"id":"precision-con-senior-16","level":"senior","profession":"consultant","title":"The confidence you can't support","scenario":"You wrote 'we are confident the target is achievable.' A director asks 'how confident, and based on what?'. You have a rough sense but never made it explicit. State your confidence honestly, with the basis.","task":"Rewrite the confidence statement with a calibrated level and the evidence that justifies it.","tips":["Calibrate: high, moderate, or contingent — and say what would change it.","Tie the confidence to specifics: comparable cases, data quality, execution risk.","Honest calibration builds trust; blanket confidence invites the puncture."],"focus":["precision","impact"]},
    {"id":"precision-con-senior-17","level":"senior","profession":"consultant","title":"The 'many clients' hand-wave","scenario":"Your proposal claims 'many clients have seen results like this.' The prospect wants proof. Replace the vague social proof with a specific, checkable example.","task":"Rewrite the claim with one named or precisely-described comparable and its actual result.","tips":["'Many clients' is unfalsifiable and therefore unpersuasive.","One specific comparable with a number beats a vague chorus.","If confidentiality binds you, describe the client precisely without naming them."],"focus":["precision","audience"],"placeholder":"A comparable industrial distributor cut procurement cost 14% in eighteen months using the same approach."},
    {"id":"precision-con-senior-18","level":"senior","profession":"consultant","title":"The precise 'now what'","scenario":"Your finding on supplier concentration ends with 'management should address this.' That's not an action. The COO needs a specific, owned, dated next step. Sharpen the recommendation.","task":"Rewrite the recommendation as a specific action with owner, mechanism, and timing.","tips":["'Address this' pushes the work back to the client — do the specifying yourself.","Name the action, the owner, and the deadline.","A vague 'now what' undoes the credibility of a sharp 'what'."],"focus":["precision","structure"],"placeholder":"Procurement should dual-source the top three concentrated categories by Q4, starting with the resin contract that expires in March."},
    {"id":"precision-con-senior-19","level":"senior","profession":"consultant","title":"The evidence a board will fact-check","scenario":"You cite a competitor's move as evidence for your recommendation, but you're working from a half-remembered news item. A director on that competitor's supply chain will know the details. Ground the claim.","task":"Rewrite the competitor claim so it's specific and checkable, with the source.","tips":["A board contains people who know your evidence firsthand — be exact.","Name the source, the date, and the specific fact, not the impression.","One fact-checkable error contaminates every other claim you make."],"focus":["precision","impact"]},
    {"id":"precision-con-senior-20","level":"senior","profession":"consultant","title":"Turning three data points into a trend","scenario":"Your slide asserts a 'clear upward trend' from three quarterly data points, two of which moved sideways. A CFO will call it noise. Either strengthen the claim with more evidence or right-size it.","task":"Rewrite the claim to match what three data points actually support.","tips":["Three points rarely make a trend — say 'early signal' if that's the truth.","If you have more evidence, bring it; if you don't, don't overreach.","A right-sized claim you can defend beats a bold one you can't."],"focus":["precision","clarity"]},
    {"id":"precision-con-senior-21","level":"senior","profession":"consultant","title":"The vague pricing recommendation","scenario":"You advise the client to 'optimize pricing.' The CEO asks 'to what, on which products, by how much?'. Your analysis has the specifics — put them in the recommendation.","task":"Rewrite the pricing recommendation with the specific products, direction, and magnitude.","tips":["'Optimize' is a verb that hides the actual decision — name it.","Which SKUs go up, which come down, by what percent.","A specific pricing move can be tested; 'optimize' can only be nodded at."],"focus":["precision","impact"],"placeholder":"Raise list price 6% on the top 20 premium SKUs and cut promotional depth on the value line from 30% to 20%."},
    {"id":"precision-con-senior-22","level":"senior","profession":"consultant","title":"The savings you can't trace","scenario":"Your total savings number is $40M but when the CFO asks to trace it to specific line items, your team can only account for $31M. The gap will torpedo credibility. Present only what you can trace.","task":"Rewrite the savings claim to show the traceable total and treat the rest honestly.","tips":["Claim only the number you can walk line by line.","An untraceable $9M isn't a bonus — it's a liability the CFO will find.","Better to present $31M you can prove than $40M you can't."],"focus":["precision","impact"]},
    {"id":"precision-con-senior-23","level":"senior","profession":"consultant","title":"The diligence claim under time pressure","scenario":"The deal team wants your verdict tonight and you're tempted to state the target's margin advantage as fact when you've only seen two months of data. Precision means saying exactly how solid the evidence is.","task":"Write the finding with an explicit confidence qualifier tied to the evidence you actually have.","tips":["Under time pressure, precision about your certainty matters more, not less.","Say what the two months show and what a full year might change.","A calibrated finding lets the deal team price the uncertainty; a false certainty misleads them."],"focus":["precision","clarity"],"placeholder":"The margin advantage looks real in two months of data, but seasonality means I can't confirm the full-year gap yet — treat 300bps as a ceiling."},
    {"id":"precision-con-senior-24","level":"senior","profession":"consultant","title":"The ROI slide the CFO will rebuild","scenario":"Your ROI slide shows a clean 4x return but hides the cost base and the timeline the CFO would need to rebuild it herself. If she can't reconstruct your math, she won't trust it. Make it transparent.","task":"Rewrite the ROI claim so the CFO can reconstruct it: investment, return, timeframe.","tips":["A return multiple without the inputs is a magic trick, not evidence.","Show the investment, the return, and over what period.","The CFO trusts the number she can rebuild, not the one she must accept."],"focus":["precision","structure"],"placeholder":"$5M invested over 18 months returns $20M by year three — a 4x return, cash-on-cash, before financing."},
    {"id":"precision-con-senior-25","level":"senior","profession":"consultant","title":"The firm-performance claim to partners","scenario":"At the partner meeting you want to say your practice 'had a strong year.' Partners will want the metrics: revenue, margin, utilization, pipeline. Replace the vague self-assessment with the numbers that let them judge.","task":"Rewrite 'strong year' as a precise statement using the metrics partners actually track.","tips":["Partners grade on numbers, not narrative — give them the four that matter.","Include the weak metric too; hiding it costs more credibility than showing it.","'Strong year' from a partner sounds like spin unless the numbers back it."],"focus":["precision","impact"],"placeholder":"Revenue up 22% to $18M, margin up 3 points to 34%, utilization at 78% — but pipeline coverage is thin at 1.4x."}
  ],
  "executive-presence": [
    {"id":"presence-con-senior-01","level":"senior","profession":"consultant","title":"Own the recommendation, don't menu it","scenario":"Your board slide presents three options with balanced pros and cons and no recommendation. The board hired you for judgment, not a menu. They'll ask 'what do you think?'. Take a position.","task":"Rewrite the slide so it recommends one option and treats the other two as the alternatives you rejected.","tips":["A neutral menu tells the board you're afraid to be wrong — own a view.","Recommend one, then say why the others lose — that's judgment, not just analysis.","'It depends on your risk appetite' is a dodge; state your read of their risk appetite."],"focus":["impact","structure"],"placeholder":"We recommend Option B. Option A is too slow for the competitive window; Option C over-commits capital you'll need elsewhere."},
    {"id":"presence-con-senior-02","level":"senior","profession":"consultant","title":"Separate fact from judgment","scenario":"In your readout you blend observed facts and your interpretation into one stream, so the CEO can't tell what's data and what's your opinion. Presence means being explicit about which is which.","task":"Rewrite a mixed passage so the fact and your judgment are clearly distinct.","tips":["Label the move: 'The data shows X. My read is Y.'","Executives trust you more when you own the interpretation as yours.","Blurring fact and judgment lets one wrong opinion discredit your facts."],"focus":["impact","precision"],"placeholder":"The fact: churn doubled in the enterprise segment. My judgment: it's a symptom of the pricing change, not the product."},
    {"id":"presence-con-senior-03","level":"senior","profession":"consultant","title":"Signpost the readout","scenario":"You launch into your findings with no roadmap, so the executives don't know how many points are coming or where you're headed. A signposted opening projects command. Add the scaffolding.","task":"Write the opening two sentences that signpost the structure before you dive in.","tips":["Tell them the shape first: 'Three findings, one recommendation, one decision I need.'","Signposting isn't filler — it lets the room follow and lets you control pace.","Announce where you'll land so they're not guessing whether you have a point."],"focus":["impact","structure"],"placeholder":"Three findings, then one recommendation. The recommendation needs a decision from you today."},
    {"id":"presence-con-senior-04","level":"senior","profession":"consultant","title":"The recommendation you're afraid to make","scenario":"Your analysis clearly points to firing the division head, but your draft softens it into 'leadership challenges in the division warrant attention.' The CEO needs your real view. Say it with presence.","task":"Write the recommendation you actually believe, stated with appropriate directness and care.","tips":["Softening a hard recommendation into vagueness serves you, not the client.","Be direct about the judgment and careful about the person — both at once.","If you believe it, say it; hedging on a people call reads as cowardice."],"focus":["impact","clarity"]},
    {"id":"presence-con-senior-05","level":"senior","profession":"consultant","title":"Command the room after a tough question","scenario":"A director challenges your central number in front of the board and you feel the urge to over-explain and concede ground. Presence is holding your position calmly while engaging the challenge. Respond with poise.","task":"Write a 2-3 sentence response that engages the challenge without retreating from your view.","tips":["Acknowledge the question, then restate your position with the evidence — don't crumble.","Over-explaining reads as insecurity; a calm, specific answer reads as command.","You can grant a fair point without abandoning the conclusion."],"focus":["impact","clarity"],"placeholder":"Fair challenge. The number holds because it's built bottom-up from actual contracts, not top-down from a market estimate — let me show you the two that drive it."},
    {"id":"presence-con-senior-06","level":"senior","profession":"consultant","title":"State the decision you need","scenario":"Your steering-committee readout describes findings beautifully but never asks the committee to actually decide anything. Presence means driving to a decision, not just informing. Close the loop.","task":"Write the closing two sentences that name the decision you need and ask for it directly.","tips":["A readout that asks for nothing wastes the committee's authority.","Name the decision, the options, and ask them to choose — today.","Executives respect a consultant who drives to a decision over one who narrates."],"focus":["impact","structure"],"placeholder":"So the decision in front of you today is whether to fund the platform now or wait a year. My recommendation is now, and here's what waiting costs."},
    {"id":"presence-con-senior-07","level":"senior","profession":"consultant","title":"The confident 'here's what I'd do'","scenario":"The CEO asks 'if this were your company, what would you do?'. Your instinct is to retreat to 'well, it depends on several factors.' She's asking for your gut with presence. Answer as an owner would.","task":"Write a 2-3 sentence answer that takes a clear position as if it were your company.","tips":["'It depends' is a non-answer to a direct request for your judgment.","Commit to one course, then name the one condition that would change it.","Answering as an owner is exactly the presence she's testing for."],"focus":["impact","clarity"]},
    {"id":"presence-con-senior-08","level":"senior","profession":"consultant","title":"Presence in the fee conversation","scenario":"The client pushes back on your $2M fee and you feel the reflex to apologize and immediately offer a discount. Presence means calmly defending the value before touching the price. Hold your ground with poise.","task":"Write a 2-3 sentence response that anchors on value and stays composed under the push.","tips":["Don't apologize for the price — explain the value that justifies it.","A reflexive discount tells the client the fee was inflated to begin with.","Composure in a fee negotiation is itself a signal of the value you bring."],"focus":["impact","audience"],"placeholder":"I understand the number is significant. It reflects a team that's done this exact transformation four times and a $40M outcome — let's talk about what that outcome is worth to you."},
    {"id":"presence-con-senior-09","level":"senior","profession":"consultant","title":"The judgment call, owned","scenario":"The evidence is genuinely ambiguous but the CEO needs a direction. Your draft lists the ambiguity and stops. Presence is making the call anyway and owning that it's a judgment. Take the position.","task":"Write the recommendation that owns the call as your judgment given the ambiguity.","tips":["When the data is ambiguous, your judgment is exactly what they're paying for.","Say 'the evidence is mixed; my judgment is X, and here's the reasoning.'","Refusing to call it because it's hard is the opposite of presence."],"focus":["impact","precision"]},
    {"id":"presence-con-senior-10","level":"senior","profession":"consultant","title":"Correcting the CEO with presence","scenario":"In the meeting the CEO states a 'fact' that your data contradicts. You could let it slide or over-apologize your way into a correction. Presence is correcting the record calmly and respectfully. Do it.","task":"Write the 2-3 sentences that correct the CEO's error with poise and evidence.","tips":["Correct the fact, not the person — 'the data actually shows' not 'you're wrong.'","Don't over-soften into inaudibility; the room needs to hear the correction.","A calm, evidenced correction raises your standing; a timid one lowers it."],"focus":["impact","clarity"],"placeholder":"One clarification on that — the data actually shows the opposite: the enterprise segment grew while SMB shrank. It changes the priority."},
    {"id":"presence-con-senior-11","level":"senior","profession":"consultant","title":"The 'I recommend against this' moment","scenario":"The CEO is excited about an acquisition your analysis says is a mistake. He wants your blessing. Presence is telling him you recommend against it, to his face, with your reasoning intact. Deliver it.","task":"Write the 2-3 sentences that recommend against the deal, directly and respectfully.","tips":["The moment they most want a yes is the moment presence matters most.","Lead with the recommendation, then the two reasons — don't bury the 'no.'","Your value is being the one person who'll tell him the truth about his favorite idea."],"focus":["impact","clarity"]},
    {"id":"presence-con-senior-12","level":"senior","profession":"consultant","title":"Owning the room's silence","scenario":"You've just made a recommendation and the board goes silent. Your instinct is to fill the silence by walking it back or adding caveats. Presence is letting your point stand and waiting. Write what you'd say next — which may be very little.","task":"Write the one sentence (or note that you'd stay silent) that holds your position through the pause.","tips":["Silence after a strong point is the point landing — don't rescue the room from it.","Adding caveats into silence undoes the recommendation you just made.","If you must speak, invite their reaction; don't retreat from your view."],"focus":["impact","concision"],"placeholder":"I'll let that sit. What's your reaction?"},
    {"id":"presence-con-senior-13","level":"senior","profession":"consultant","title":"Presence in writing: the assertive memo","scenario":"Your recommendation memo is written in the passive voice throughout — 'it is recommended that consideration be given.' The passivity drains all authority. Rewrite it in the active, first-person voice of someone who owns the view.","task":"Rewrite a passive recommendation passage in active, first-person, owned language.","tips":["'It is recommended' hides the recommender — say 'we recommend.'","Active voice puts an owner behind every claim.","Passivity in a recommendation reads as hedging your bets."],"focus":["impact","clarity"]},
    {"id":"presence-con-senior-14","level":"senior","profession":"consultant","title":"The strong open to a hostile room","scenario":"You're presenting cost cuts to a leadership team that resents outside consultants. A weak, apologetic open will lose them for the hour. Presence is opening with quiet authority and a stake they share. Write the open.","task":"Write the opening 2-3 sentences that establish presence with a resistant audience.","tips":["Don't open by justifying your presence — open with something they care about.","Calm authority, not apology; you're there because leadership asked.","Name the shared goal so you're on their side of the table from sentence one."],"focus":["impact","audience"]},
    {"id":"presence-con-senior-15","level":"senior","profession":"consultant","title":"Distinguish 'the data suggests' from 'I conclude'","scenario":"Your slide says 'the data suggests we should exit the market.' Data doesn't conclude — you do. Presence is owning the conclusion as your professional judgment rather than hiding behind the data.","task":"Rewrite the claim so you own the conclusion and the data is the support.","tips":["Data suggests; consultants conclude — own the verb.","'I conclude X because the data shows Y' is more authoritative than 'the data suggests X.'","Hiding behind the data lets you disown the call if it's unpopular — don't."],"focus":["impact","precision"],"placeholder":"I recommend exiting the market. The data behind that is clear: three years of share loss and no path to profitability."},
    {"id":"presence-con-senior-16","level":"senior","profession":"consultant","title":"The composed answer to 'you're wrong'","scenario":"A CFO says flatly, 'Your whole analysis is wrong.' The room turns to you. Presence is not defensiveness or collapse but a composed, curious response that engages the substance. Write it.","task":"Write the 2-3 sentence composed response to the blunt accusation.","tips":["Meet the heat with calm curiosity, not defensiveness — 'help me see where.'","Separate the emotion from the substance; engage the substance.","Composure under direct attack is the clearest signal of presence there is."],"focus":["impact","clarity"],"placeholder":"That's a strong statement — help me understand which part. If the analysis is wrong, I want to know before the board does, so walk me through it."},
    {"id":"presence-con-senior-17","level":"senior","profession":"consultant","title":"The recommendation with a clear rationale hierarchy","scenario":"You have five reasons for your recommendation and you present them as equals, which reads as scattered. Presence is naming the one reason that would stand alone, then the support. Prioritize with authority.","task":"Write the recommendation with the single decisive reason first, then the supporting reasons compressed.","tips":["Lead with the reason that alone would justify the call — that's command.","Presenting five equal reasons signals you're not sure which one matters.","The supporting reasons reinforce; they don't share the podium."],"focus":["impact","structure"]},
    {"id":"presence-con-senior-18","level":"senior","profession":"consultant","title":"Presence when you agree with the client's rival","scenario":"Two executives are at war over strategy and your analysis backs one of them. Presence is stating your independent conclusion without appearing to take sides in their politics. Thread it.","task":"Write the 2-3 sentences that state your conclusion as independent judgment, not alliance.","tips":["Anchor to the evidence, not the person your conclusion happens to favor.","Name the criteria you used so it reads as analysis, not allegiance.","Presence here is being visibly above the politics while still taking a position."],"focus":["impact","audience"]},
    {"id":"presence-con-senior-19","level":"senior","profession":"consultant","title":"The confident scope of what you don't cover","scenario":"An executive asks about an area outside your engagement. A low-presence move is to bluff an answer. Presence is naming the boundary confidently and pointing to who owns it, without seeming evasive.","task":"Write a 2-3 sentence response that owns the boundary of your scope with authority.","tips":["Confidently saying 'that's outside what we looked at' beats a bluffed answer.","Point to who does own it — that's helpful, not a dodge.","Presence includes knowing and stating the edges of your knowledge."],"focus":["impact","clarity"]},
    {"id":"presence-con-senior-20","level":"senior","profession":"consultant","title":"The recommendation that costs the sponsor politically","scenario":"Your recommendation is right for the company but embarrassing for the sponsor who championed the failed program. Presence is delivering it clearly while giving the sponsor a dignified path. Write the framing.","task":"Write the 2-3 sentences that deliver the recommendation and preserve the sponsor's standing.","tips":["Don't soften the recommendation to protect the sponsor — reframe the narrative instead.","Give them the 'we learned' story: the pilot did its job by revealing this.","Presence is being clear and generous at the same time."],"focus":["impact","audience"],"placeholder":"The pilot did exactly what a pilot should — it surfaced this before you spent the real money. The recommendation now is to stop and redirect."},
    {"id":"presence-con-senior-21","level":"senior","profession":"consultant","title":"Command in the crisis update","scenario":"The engagement hit a serious problem and you're briefing the senior partner. A panicked, apologetic update erodes confidence. Presence is a calm, structured account: what happened, what you're doing, what you need. Write it.","task":"Write the 3-4 sentence crisis update that projects control.","tips":["State the problem plainly, then immediately what you're doing about it.","Panic is contagious; so is composure — choose which you transmit.","End with the specific help you need, not an apology."],"focus":["impact","structure"]},
    {"id":"presence-con-senior-22","level":"senior","profession":"consultant","title":"The declarative title, not the coy one","scenario":"Your key slide is titled with a question — 'Should the company enter the adjacency?' — which makes you look undecided. Presence is a declarative title that states your answer. Rewrite it.","task":"Rewrite the question-title as a declarative statement of your position.","tips":["A question-title makes the reader do your thinking — take the position instead.","The title is your conclusion; the slide is the support.","Declarative titles read as command; coy ones read as fence-sitting."],"focus":["impact","concision"],"placeholder":"Enter the adjacency now — the window closes in eighteen months."},
    {"id":"presence-con-senior-23","level":"senior","profession":"consultant","title":"Presence when the client wants you to hedge","scenario":"The sponsor asks you to 'add more nuance' to a recommendation because your clarity makes her nervous. Presence is respectfully protecting the clarity the board actually needs, not caving to her discomfort. Respond.","task":"Write a 2-3 sentence response that holds the clarity while acknowledging her concern.","tips":["Her nervousness isn't a reason to muddy what the board needs to decide.","Offer to add the nuance as backup, not to dilute the headline.","Protecting clarity for the decision-maker is a form of presence toward her too."],"focus":["impact","audience"]},
    {"id":"presence-con-senior-24","level":"senior","profession":"consultant","title":"The firm-leadership stance","scenario":"At the partner meeting, a proposal to chase a low-margin megaclient is gathering momentum you think is a mistake. Presence is stating your dissent clearly to your peers, not going along quietly. Write your intervention.","task":"Write the 3-4 sentences that voice your dissent to the partnership with authority.","tips":["Dissenting to peers takes the same presence as dissenting to a client.","Lead with your position, then the specific risk you see the room ignoring.","Going along quietly and being right later serves no one."],"focus":["impact","clarity"]},
    {"id":"presence-con-senior-25","level":"senior","profession":"consultant","title":"The clean close that lands the ask","scenario":"You've delivered a strong readout but your close trails off into 'so, yeah, those are our thoughts, happy to discuss.' The weak ending undercuts everything. Presence is a clean, deliberate close that lands the recommendation and the ask.","task":"Write a 2-3 sentence close that restates the recommendation and drives to the decision.","tips":["The last thing you say is what the room remembers — make it the recommendation.","'Happy to discuss' surrenders the frame; ask for the decision instead.","A deliberate close signals you meant every word that came before."],"focus":["impact","structure"],"placeholder":"So the recommendation is to close Riverside and reinvest the savings in the two growth plants. I'd like your decision today — what questions stand between you and yes?"}
  ],
  "answering-under-pressure": [
    {"id":"pressure-con-senior-01","level":"senior","profession":"consultant","title":"Answer the question actually asked","scenario":"A director asks 'Is the target achievable this year?' and your instinct is to launch into the methodology behind the target. She asked a yes/no. Answer that first, then support.","task":"Write the 2-3 sentence answer that leads with yes or no, then the one condition.","tips":["Answer the literal question in the first three words.","Methodology is what she'll ask for next — if she asks.","Leading with process instead of answer reads as dodging."],"focus":["clarity","impact"],"placeholder":"Yes, this year — but only if the plant closure lands by Q3. Slip that, and it moves to next year."},
    {"id":"pressure-con-senior-02","level":"senior","profession":"consultant","title":"The hostile 'so what have you actually done?'","scenario":"Six weeks into a rocky engagement, the frustrated sponsor demands 'What have you actually accomplished?'. Defensiveness will make it worse. Answer with specifics, calmly, then pivot to the path forward.","task":"Write a 3-4 sentence response that answers with concrete progress and redirects to what's next.","tips":["Meet the challenge with specifics, not a defense of your effort.","Name two or three concrete things delivered — facts cool the temperature.","Then pivot forward: here's what you'll see in the next two weeks."],"focus":["clarity","impact"]},
    {"id":"pressure-con-senior-03","level":"senior","profession":"consultant","title":"The honest 'I don't know' with a path","scenario":"In the board meeting a director asks a question your analysis simply hasn't reached yet. Bluffing risks getting caught; a bare 'I don't know' looks unprepared. Give the honest answer plus a path.","task":"Write the 2-3 sentence response: honest admission plus exactly how and when you'll answer.","tips":["'I don't know yet' is credible; a bluff a director can puncture is fatal.","Immediately attach the path: what you'll do and by when.","Boards trust the consultant who admits limits over the one who fakes certainty."],"focus":["clarity","precision"],"placeholder":"We haven't sized that yet — it wasn't in scope. I can have a defensible number by next Friday if you want it."},
    {"id":"pressure-con-senior-04","level":"senior","profession":"consultant","title":"Pushback with a specific counter","scenario":"The CFO says 'Your savings number is inflated — no one ever hits these.' Instead of defending abstractly, counter with the specific evidence that this number is grounded. Answer the pushback with data.","task":"Write a 2-3 sentence response that meets the skepticism with a specific, grounded counter.","tips":["Don't argue that your number is right in general — show why this one is grounded.","Cite the specific basis: bottom-up build, comparable capture rates, conservative assumptions.","Specifics defeat skepticism; assertions feed it."],"focus":["precision","impact"],"placeholder":"That's usually true — which is why this is built bottom-up from actual contracts, and I've already discounted it to a 60% capture rate. The $33M floor is conservative."},
    {"id":"pressure-con-senior-05","level":"senior","profession":"consultant","title":"The loaded question in the workshop","scenario":"A skeptical executive asks 'Did you talk to anyone who actually runs this business, or just look at spreadsheets?'. The question is a trap and an insult. Answer the legitimate concern underneath without taking the bait.","task":"Write a 2-3 sentence response that answers the real concern and defuses the hostility.","tips":["Find the fair question inside the loaded one and answer that.","Don't get defensive about the insult — the room is watching your composure.","Concrete evidence of your fieldwork disarms the charge better than protest."],"focus":["clarity","audience"],"placeholder":"Both — I spent two days on the floor at Riverside and interviewed eleven of your plant managers. Here's what they told me that the spreadsheets missed."},
    {"id":"pressure-con-senior-06","level":"senior","profession":"consultant","title":"When the CEO reframes your point wrongly","scenario":"The CEO restates your recommendation back to the board in a way that distorts it in a direction he prefers. Under pressure you must correct the record without contradicting him publicly. Thread it.","task":"Write the 2-3 sentences that gently restore the accurate version of your recommendation.","tips":["Affirm what he got right, then sharpen the part he bent.","'Let me make sure I said this clearly' reframes the correction as your error, not his.","The board needs the accurate version on the record — that's your job here."],"focus":["clarity","audience"],"placeholder":"That's most of it — let me sharpen one piece. I'm recommending we close Riverside, not consolidate into it. The difference matters for the headcount plan."},
    {"id":"pressure-con-senior-07","level":"senior","profession":"consultant","title":"The 'give me a number now' demand","scenario":"The deal partner demands a valuation number on the spot, before your analysis is finished. Refusing looks weak; guessing is dangerous. Give a bounded, honest answer under the pressure.","task":"Write a 2-3 sentence answer that provides a defensible range and flags what would tighten it.","tips":["A range with a stated confidence beats a false point estimate.","Name what you'd need to narrow it — that shows rigor, not evasion.","Under pressure, precision about your uncertainty is the professional move."],"focus":["precision","clarity"],"placeholder":"My current range is 6 to 6.5 times EBITDA — I'd stake my reputation on 'under 7.' Two more days on the customer contracts would tighten it to a tenth."},
    {"id":"pressure-con-senior-08","level":"senior","profession":"consultant","title":"Challenged on your independence","scenario":"An executive accuses you of telling the CEO what he wants to hear. Your credibility rests on independence. Answer the charge directly, with evidence that you've delivered unwelcome messages before. Defend the record.","task":"Write a 2-3 sentence response that answers the independence charge with proof.","tips":["Don't protest your integrity abstractly — point to an unwelcome thing you've told this client.","Independence is proven by the inconvenient conclusion, not the assertion.","Stay calm; heat makes the accusation look landed."],"focus":["impact","clarity"]},
    {"id":"pressure-con-senior-09","level":"senior","profession":"consultant","title":"The question you're not ready for at the board","scenario":"A director asks about a regulatory scenario you genuinely haven't considered. You feel the room waiting. Under pressure, you must neither bluff nor freeze. Buy the right amount of time honestly.","task":"Write the 2-3 sentences that acknowledge the gap and commit to a rigorous answer.","tips":["Name that it's a good question you want to answer properly, not off the cuff.","Commit to a specific follow-up rather than improvising a weak answer live.","Directors respect 'let me get you a real answer' over a confident guess."],"focus":["clarity","precision"]},
    {"id":"pressure-con-senior-10","level":"senior","profession":"consultant","title":"Two executives, opposite demands","scenario":"In the room, the COO wants speed and the CFO wants certainty, and both look to you to endorse their side. Under pressure you must answer both without picking a political side. Hold the substance.","task":"Write a 2-3 sentence answer that addresses both demands honestly without taking a political side.","tips":["Answer the substance both are really asking about, not their rivalry.","Name the genuine trade-off so the choice is theirs, not yours to broker.","Refusing to be weaponized by either is the credible move."],"focus":["clarity","audience"]},
    {"id":"pressure-con-senior-11","level":"senior","profession":"consultant","title":"The gotcha on an old number","scenario":"A director says 'Three weeks ago you told us $50M, now it's $40M — which is it?'. The number changed for good reasons. Under pressure, explain the change without sounding like you're backpedaling.","task":"Write a 2-3 sentence answer that owns the revision and explains why the new number is better.","tips":["Own the change directly — 'the number came down, and here's why it's now more reliable.'","A refined number is a strength; frame it as rigor, not retreat.","Defensiveness makes a normal revision look like an error."],"focus":["precision","impact"],"placeholder":"It came down, and it should have — three weeks ago it was top-down; now it's built from your actual contracts. $40M is the number I'll defend to the board."},
    {"id":"pressure-con-senior-12","level":"senior","profession":"consultant","title":"When your recommendation is called naive","scenario":"A veteran executive says 'You've clearly never run an operation — this won't work in the real world.' Under pressure, answer the substantive objection rather than the credential attack. Engage the 'why.'","task":"Write a 2-3 sentence response that surfaces and engages the real operational objection.","tips":["Ask what specifically won't work — turn the insult into a concrete objection you can address.","Don't defend your experience; demonstrate that you understand his.","Engaging the operational reality shows more presence than protesting."],"focus":["clarity","audience"],"placeholder":"You may be right that I'm missing something operational — tell me where it breaks. If it's the changeover time on line three, I've accounted for that; if it's something else, I want to hear it."},
    {"id":"pressure-con-senior-13","level":"senior","profession":"consultant","title":"The interruption that derails you","scenario":"You're two sentences into a critical point when a senior executive cuts you off with a tangent. Under pressure, you must acknowledge, park it, and reclaim your thread without seeming to dismiss him.","task":"Write the 2-3 sentences that handle the interruption and return to your point.","tips":["Acknowledge his point and name when you'll return to it — don't ignore or fully cede.","Reclaim your thread explicitly so the room follows: 'coming back to the core issue.'","Losing your thread to every interruption erodes command."],"focus":["clarity","structure"]},
    {"id":"pressure-con-senior-14","level":"senior","profession":"consultant","title":"The 'just tell me it'll be fine' pressure","scenario":"The anxious sponsor, the night before the board meeting, wants you to reassure her that everything will go smoothly. The honest answer includes real risk. Under pressure to comfort, stay truthful and steadying.","task":"Write a 2-3 sentence response that is honest about the risk and genuinely steadying.","tips":["False reassurance now becomes your problem tomorrow — don't give it.","Be steadying through preparation, not through denial: 'here's how we handle the hard question.'","Honesty delivered calmly is more reassuring than a promise you can't keep."],"focus":["clarity","audience"]},
    {"id":"pressure-con-senior-15","level":"senior","profession":"consultant","title":"Cornered on a confidential fact","scenario":"An executive presses you for information about another client that you're bound to keep confidential. Under pressure, you must decline clearly without being evasive or damaging trust. Draw the line cleanly.","task":"Write a 2-3 sentence response that declines on confidentiality grounds with poise.","tips":["Name the confidentiality plainly — it's a strength, not a dodge.","Point out that you protect his confidences the same way.","A clean, principled decline builds trust; a squirm destroys it."],"focus":["clarity","impact"],"placeholder":"I can't share anything about another client's situation — the same way I'd never share yours. What I can do is talk about what's public and what's generally true in the industry."},
    {"id":"pressure-con-senior-16","level":"senior","profession":"consultant","title":"The rapid-fire board questions","scenario":"Three directors fire three different questions at you in fifteen seconds. Under pressure, panic makes you answer poorly. Take control by structuring the answers rather than scrambling. Order the chaos.","task":"Write the opening sentence that structures your response to multiple simultaneous questions.","tips":["Name that you'll take them in order — that alone projects control.","Answer the most decision-relevant one first, briefly, then the others.","Structuring the chaos is the presence move; scrambling is not."],"focus":["structure","clarity"],"placeholder":"Three questions — let me take them in order: the cost first, the timeline second, the risk third."},
    {"id":"pressure-con-senior-17","level":"senior","profession":"consultant","title":"When you're wrong and they caught it","scenario":"A director points out a genuine error in your analysis in front of the board. Under pressure, the temptation is to minimize or deflect. The credible move is to own it cleanly and say what it does and doesn't change.","task":"Write the 2-3 sentences that own the error and scope its impact.","tips":["Concede the error immediately and specifically — no minimizing.","Then scope it: does it change the recommendation or not?","Owning a real mistake well can raise your credibility, not lower it."],"focus":["clarity","impact"],"placeholder":"You're right, and thank you — that figure is wrong. The good news is it doesn't move the recommendation; the gap is $2M, not $12M, and the case holds either way."},
    {"id":"pressure-con-senior-18","level":"senior","profession":"consultant","title":"The 'why should we pay for this?' challenge","scenario":"Mid-engagement, a new executive who wasn't part of the decision asks pointedly why the firm is paying for consultants at all. Under pressure, answer the value question directly, without defensiveness. Make the case.","task":"Write a 2-3 sentence answer that makes the value case to a skeptic, calmly.","tips":["Answer with the specific outcome, not a defense of consulting.","Name what the client gets that they couldn't do internally or as fast.","Composure plus a concrete value point beats any abstract justification."],"focus":["impact","audience"]},
    {"id":"pressure-con-senior-19","level":"senior","profession":"consultant","title":"Holding the line on a firm recommendation","scenario":"The board is uncomfortable with your recommendation and keeps probing for a softer version. Under repeated pressure, you must hold the recommendation while genuinely engaging each concern. Stay firm and open at once.","task":"Write a 2-3 sentence response to the third round of 'are you sure?' that holds firm without stonewalling.","tips":["Reaffirm the recommendation, then engage the specific new concern each time.","Firmness isn't repetition — bring a fresh piece of evidence or reasoning.","Caving to persistent pressure tells the board your conviction was thin."],"focus":["impact","clarity"]},
    {"id":"pressure-con-senior-20","level":"senior","profession":"consultant","title":"The trap between two of your slides","scenario":"An executive points out that slide 8 says growth is slowing and slide 22 assumes it accelerates. Under pressure, you must reconcile the apparent contradiction honestly and fast, or lose the room's trust.","task":"Write the 2-3 sentences that reconcile the two slides or concede the tension.","tips":["If there's a real reconciliation — different segments, different periods — state it crisply.","If it's a genuine inconsistency, concede it and say which slide is right.","Bluffing a reconciliation that doesn't exist is how you lose the whole deck."],"focus":["precision","clarity"],"placeholder":"Good catch — those are different segments. Slide 8 is the legacy business slowing; slide 22 is the adjacency accelerating. The blended number is on slide 24."},
    {"id":"pressure-con-senior-21","level":"senior","profession":"consultant","title":"The emotional executive in the room","scenario":"Your recommendation to consolidate his division has the regional president visibly angry and talking over you. Under pressure, you must acknowledge the emotion, stay steady, and keep the substance on track. De-escalate.","task":"Write the 2-3 sentences that acknowledge his reaction and steer back to substance.","tips":["Name the stakes for him honestly — dismissing the emotion inflames it.","Stay level; matching his heat escalates, absorbing it de-escalates.","Then offer a concrete way for him to shape the outcome."],"focus":["audience","clarity"]},
    {"id":"pressure-con-senior-22","level":"senior","profession":"consultant","title":"Answering when you disagree with your own partner","scenario":"In front of the client, your senior partner states a view you think is wrong. A director asks you directly whether you agree. Under pressure, you must be honest without undermining your partner publicly. Thread the needle.","task":"Write a 2-3 sentence answer that's honest without publicly contradicting your partner.","tips":["Find the part you genuinely agree with and lead with it.","Add your view as a build or a nuance, not a contradiction.","Save the real disagreement for a private conversation, not the client room."],"focus":["clarity","audience"]},
    {"id":"pressure-con-senior-23","level":"senior","profession":"consultant","title":"The 'guarantee it' demand","scenario":"The CEO says he'll only proceed if you guarantee the outcome. You can't honestly guarantee it. Under pressure to close, you must decline the guarantee while still giving him grounds for confidence. Hold the line.","task":"Write a 2-3 sentence response that declines the guarantee and offers grounded confidence instead.","tips":["Never guarantee an outcome you don't control — it destroys credibility later.","Replace the guarantee with the track record and the risk management around it.","'I can't guarantee it, but here's why I'm confident' is the honest, stronger answer."],"focus":["clarity","impact"],"placeholder":"I can't guarantee the outcome — anyone who does is selling you something. What I can tell you is we've done this four times, hit the target three, and I know exactly why the fourth missed."},
    {"id":"pressure-con-senior-24","level":"senior","profession":"consultant","title":"The follow-up you can't fully answer live","scenario":"A director asks a sharp follow-up that exposes a real limitation in your analysis. Under pressure, you must acknowledge the limitation honestly, give your best current read, and commit to closing the gap.","task":"Write the 2-3 sentences that give a partial honest answer plus a commitment to complete it.","tips":["Separate what you can answer now from what you can't — answer the first part fully.","Give your directional read on the rest, clearly flagged as preliminary.","Commit to the full answer with a date; don't let the gap hang."],"focus":["clarity","precision"]},
    {"id":"pressure-con-senior-25","level":"senior","profession":"consultant","title":"The final 'what would you do' from the chair","scenario":"After all the analysis, the board chair looks at you and asks, plainly, 'Forget the slides — what would you do?'. Under the pressure of the whole room, you must give your unvarnished judgment in a sentence or two.","task":"Write the 2-3 sentence answer that gives your clear personal judgment, unhedged.","tips":["This is the moment they've been waiting for — don't retreat to the deck.","One clear course, one reason, stated as your own conviction.","Hedging here wastes every hour of analysis that earned you the question."],"focus":["impact","clarity"],"placeholder":"I'd close Riverside this year and put the savings into the two growth plants — no hedging. The window to reinvest is now, and waiting a year costs you the head start."}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-con-senior-01","level":"senior","profession":"consultant","title":"Before and after the transformation","scenario":"Your transformation pitch lists activities and deliverables but never paints the change: what the company looks like today versus what it becomes. Executives buy the after-state, not the workplan. Frame the change.","task":"Write a 3-4 sentence before/after that makes the transformation vivid.","tips":["Contrast the painful present with the specific better future — that gap is the sale.","Make the after-state concrete: what a Tuesday looks like when it's done.","The workplan is how you get there; the after-state is why they'd go."],"focus":["impact","audience"],"placeholder":"Today, your planners spend three weeks reconciling forecasts by hand and still miss. In eighteen months, that's a two-day automated cycle, and your service level goes from 88% to 96%."},
    {"id":"narrative-con-senior-02","level":"senior","profession":"consultant","title":"Make the stakes concrete","scenario":"Your recommendation to fix pricing is technically sound but the CEO isn't moved because the stakes are abstract — 'margin erosion.' Turn the abstraction into something he can feel. Make the cost of inaction vivid.","task":"Rewrite the stakes as a concrete, vivid consequence of doing nothing.","tips":["'Margin erosion' is a term; 'giving a competitor $30M a year' is a picture.","Anchor the stakes to something the CEO personally cares about.","Concrete stakes create urgency that abstract ones can't."],"focus":["impact","precision"],"placeholder":"Every quarter you wait, discounting hands a competitor $8M and trains your sales team to give it away. In two years that's a habit you can't unlearn."},
    {"id":"narrative-con-senior-03","level":"senior","profession":"consultant","title":"Pre-empt the strongest objection","scenario":"You're pitching a bold market entry, and you know the CFO's strongest objection will be capital risk. If you ignore it, he'll raise it and win. Address it inside your narrative before he can. Pre-empt.","task":"Write the 2-3 sentences that raise and defuse the CFO's strongest objection within your pitch.","tips":["Name the objection yourself — it disarms it and signals you've thought it through.","Address the strongest version, not a strawman.","Pre-empting the CFO's point turns his ammunition into your credibility."],"focus":["impact","structure"],"placeholder":"The obvious worry is capital at risk — so we've structured it in stages: $5M to prove the model before a dollar more, with a clean exit if the first cohort misses."},
    {"id":"narrative-con-senior-04","level":"senior","profession":"consultant","title":"The proposal that tells a story","scenario":"Your proposal reads as a list of workstreams and fees. It doesn't tell the client a story about their own situation and future. Reframe the proposal as a narrative the client sees themselves in. Open with their story.","task":"Write the opening 3-4 sentences that cast the client as the protagonist of a change story.","tips":["Start with where they are and the fork they face — make them the hero.","The engagement is the journey, not the point of the story.","Clients buy proposals that understand their story better than they've told it."],"focus":["audience","impact"]},
    {"id":"narrative-con-senior-05","level":"senior","profession":"consultant","title":"The turnaround narrative for the board","scenario":"You're presenting a turnaround plan to a demoralized board that's seen two failed attempts. A dry plan won't move them. You need a narrative that acknowledges the failures and makes this path feel different and winnable.","task":"Write the 3-4 sentence narrative frame: honest past, credible turning point, winnable future.","tips":["Acknowledge the failed attempts honestly — denial kills credibility.","Name what's genuinely different this time, specifically.","The board needs to believe the turn is possible before they'll fund it."],"focus":["impact","audience"]},
    {"id":"narrative-con-senior-06","level":"senior","profession":"consultant","title":"Selling the unglamorous recommendation","scenario":"Your best recommendation is boring: fix the order-to-cash process. The CEO wants a bold growth story. You must make the unglamorous fix feel like the foundation of the growth he wants. Frame it persuasively.","task":"Write a 2-3 sentence frame that makes the boring fix feel essential to the exciting goal.","tips":["Connect the unglamorous work to the outcome the executive actually wants.","Position it as the foundation without which the exciting play fails.","Persuasion is linking your recommendation to their existing desire."],"focus":["impact","audience"],"placeholder":"You can't scale a growth engine on a billing system that leaks 4% of revenue — fixing order-to-cash isn't the exciting part, it's what makes the exciting part possible."},
    {"id":"narrative-con-senior-07","level":"senior","profession":"consultant","title":"The one vivid example that lands the point","scenario":"Your point about supply-chain fragility is buried in aggregate statistics. It's not landing. A single vivid example — one product, one stockout, one lost customer — would make it real. Find the story in the data.","task":"Write the one concrete example that dramatizes the aggregate finding.","tips":["One vivid case sticks where a hundred data points slide off.","Choose the example that connects to money or a customer the executive knows.","Follow the story with the number so it has both heart and rigor."],"focus":["impact","precision"]},
    {"id":"narrative-con-senior-08","level":"senior","profession":"consultant","title":"Reframe the cost cut as investment","scenario":"The CEO hears your $40M cost program as 'shrinking the company.' The same program funds the growth agenda he cares about. Reframe the narrative from cutting to redeploying. Change the frame.","task":"Write a 2-3 sentence reframe that turns the cost story into a redeployment story.","tips":["'Cutting' is loss; 'freeing up capital to invest' is gain — same dollars, different story.","Name what the freed money buys that he wants.","The frame determines whether the board sees defense or offense."],"focus":["impact","audience"],"placeholder":"This isn't about shrinking — it's about freeing $40M that's currently trapped in inefficiency and redeploying it into the two markets where you can actually win."},
    {"id":"narrative-con-senior-09","level":"senior","profession":"consultant","title":"Persuading the skeptic with their own logic","scenario":"The COO distrusts consultants and any recommendation you push. Persuasion here means leading him to the conclusion using his own stated priorities, so it feels like his idea. Build the path.","task":"Write the 3-4 sentences that walk the COO to your recommendation using his own stated priorities.","tips":["Start from a premise he's already committed to out loud.","Let each step follow from his logic so the conclusion feels self-generated.","People defend conclusions they reach themselves far more than ones you hand them."],"focus":["audience","impact"]},
    {"id":"narrative-con-senior-10","level":"senior","profession":"consultant","title":"The stakes for a specific person","scenario":"You're persuading the CHRO to back a delayering that helps the company but she reads as a threat to her people agenda. Persuasion means finding the version where she and her people win. Frame her stake.","task":"Write a 2-3 sentence frame that makes the change serve the CHRO's own agenda.","tips":["Find the genuine win for her, not a rhetorical trick.","Connect the change to something she's publicly championed.","Persuasion fails when the listener can't see themselves winning."],"focus":["audience","impact"]},
    {"id":"narrative-con-senior-11","level":"senior","profession":"consultant","title":"The urgency without the fear-mongering","scenario":"You need the board to act now, not next year, but overhyped urgency reads as manipulation. Build genuine, evidenced urgency: a real window that's closing for real reasons. Make the clock credible.","task":"Write a 2-3 sentence case for acting now that's urgent but honest.","tips":["Ground the urgency in a specific, dated external reality — a competitor, a regulation, a window.","Overstated urgency you can't back destroys trust — calibrate it.","Real urgency persuades; manufactured urgency insults the room's intelligence."],"focus":["impact","precision"],"placeholder":"The window is real and dated: your main competitor's non-compete expires in fourteen months, and once they can hire your regional teams, this play gets twice as expensive."},
    {"id":"narrative-con-senior-12","level":"senior","profession":"consultant","title":"Address the elephant before you pitch","scenario":"You're pitching a follow-on engagement, but everyone knows the last phase ran over budget. If you don't name it, your pitch sounds oblivious. Address the elephant, then pivot to the case. Clear the air first.","task":"Write the 2-3 sentences that name the past problem and turn it into a reason to trust you now.","tips":["Name the overrun before they do — it converts a liability into candor.","Say specifically what you learned and changed.","Owning the hard truth earns the right to make the pitch."],"focus":["audience","impact"]},
    {"id":"narrative-con-senior-13","level":"senior","profession":"consultant","title":"The analogy that unlocks the strategy","scenario":"The board can't grasp why the platform play matters until you give them an analogy they already understand. The right analogy makes an unfamiliar strategy instantly legible. Find it.","task":"Write the analogy plus the one sentence that connects it to the client's decision.","tips":["A good analogy borrows understanding the audience already has.","Then immediately map it back — analogy without the bridge is just a story.","Choose an analogy from their world, not a consulting cliché."],"focus":["audience","clarity"]},
    {"id":"narrative-con-senior-14","level":"senior","profession":"consultant","title":"Persuade the family owner to change","scenario":"The 71-year-old founder resists professionalizing governance because it feels like betraying what he built. Persuasion means framing the change as the truest way to honor his legacy, not abandon it. Reframe the change.","task":"Write a 2-3 sentence frame that casts the change as protecting his legacy, not replacing it.","tips":["His resistance is about meaning, not mechanics — speak to the meaning.","Frame governance as what lets the company outlive him, which is what he wants.","Persuade by aligning with his deepest goal, not overriding it."],"focus":["audience","impact"],"placeholder":"Everything you've built rests on you being in the building. The only way it outlives you — the way your father's work outlived him — is a structure that can run without you in the room."},
    {"id":"narrative-con-senior-15","level":"senior","profession":"consultant","title":"The three-act client story","scenario":"Your final readout is a pile of findings with no arc. A three-act structure — the world they knew, the disruption, the new path — would make it persuasive and memorable. Build the arc.","task":"Write one sentence for each of the three acts of the client's story.","tips":["Act one: the stable world and the assumptions it rested on.","Act two: the disruption that broke those assumptions.","Act three: the path forward — your recommendation, as the resolution."],"focus":["structure","impact"]},
    {"id":"narrative-con-senior-16","level":"senior","profession":"consultant","title":"Pre-empt the 'we tried that' objection","scenario":"Your recommendation resembles something the client attempted and abandoned two years ago. The instant objection will be 'we tried that, it failed.' Address why this time is genuinely different before they raise it.","task":"Write the 2-3 sentences that pre-empt 'we tried that' with a real distinction.","tips":["Acknowledge the prior attempt specifically — vagueness signals you didn't know.","Name the concrete difference: different conditions, different design, different capability.","'This time is different' only persuades if the difference is real and named."],"focus":["impact","precision"]},
    {"id":"narrative-con-senior-17","level":"senior","profession":"consultant","title":"The persuasive close of the proposal","scenario":"Your proposal ends with a fee table and a signature line — no call to the future, no reason to feel the moment. A persuasive close makes the client want to say yes now. Write a close that moves them.","task":"Write a 2-3 sentence persuasive close that connects the decision to their aspiration.","tips":["End on the after-state, not the price — remind them what yes buys.","Make the moment feel consequential without manufacturing drama.","The close is your last chance to make them feel the decision, not just calculate it."],"focus":["impact","audience"]},
    {"id":"narrative-con-senior-18","level":"senior","profession":"consultant","title":"Sell the harder-but-right option","scenario":"You're recommending the harder of two paths because it's genuinely better long-term. The easy path is tempting to the board. Persuade them to choose the harder road by making its payoff vivid and its risk manageable.","task":"Write a 3-4 sentence case for the harder path that makes its payoff feel worth the difficulty.","tips":["Acknowledge honestly that it's harder — pretending otherwise loses trust.","Make the long-term payoff concrete enough to outweigh the near-term pain.","Show the risk is managed, so 'harder' doesn't read as 'reckless.'"],"focus":["impact","structure"]},
    {"id":"narrative-con-senior-19","level":"senior","profession":"consultant","title":"The data story with a villain","scenario":"Your margin analysis is accurate but inert. Giving it a clear antagonist — the specific practice that's destroying value — makes it a story the executives rally against. Name the villain.","task":"Write a 2-3 sentence framing that names the specific practice as the antagonist to defeat.","tips":["A clear antagonist gives the room something to unite against.","Make it a practice or condition, not a person, unless you want a fight.","'Here's what's eating your margin' is more mobilizing than 'margin is down.'"],"focus":["impact","audience"],"placeholder":"There's one habit quietly eating your margin: unmanaged sales discretion at the deal desk. It's not a person — it's a broken guardrail, and it's costing you $18M a year."},
    {"id":"narrative-con-senior-20","level":"senior","profession":"consultant","title":"Persuade your own team to push harder","scenario":"Your engagement team is deflated after a tough steering committee. You need to re-motivate them with a narrative about why the work matters and that the hard part is nearly done. Rally them.","task":"Write a 3-4 sentence rallying message that reframes the setback and renews the mission.","tips":["Acknowledge the hard meeting honestly before you pivot.","Connect their work to the real impact it will have on the client.","Give them a concrete near-term win to aim at."],"focus":["impact","audience"]},
    {"id":"narrative-con-senior-21","level":"senior","profession":"consultant","title":"The pitch to the consultant-skeptic founder","scenario":"The founder opened with 'consulting decks never change anything.' You must persuade him not with credentials but with a narrative about his specific company that he hasn't heard articulated. Win him with insight.","task":"Write the 3-4 sentence pitch that persuades through a sharper story of his own business.","tips":["Persuade by naming his problem more precisely than he has.","Skip the framework; the insight is the proof of value.","Make him feel understood before you make him feel sold to."],"focus":["audience","impact"]},
    {"id":"narrative-con-senior-22","level":"senior","profession":"consultant","title":"The renewal case as a story of momentum","scenario":"You're pitching a renewal and your draft lists what you'll do next. More persuasive is a story of momentum: what's already changed, the flywheel that's started, why stopping now wastes it. Frame the momentum.","task":"Write a 2-3 sentence renewal frame built on the momentum already created.","tips":["Show the flywheel that's begun turning — stopping now loses the energy.","Concrete early results make the case for continuing better than promises do.","'Don't stop when it's starting to work' is a powerful, honest frame."],"focus":["impact","audience"],"placeholder":"The savings engine you built is now delivering $1M a month and accelerating — pulling the team out now is like taking your foot off the gas at the top of the hill."},
    {"id":"narrative-con-senior-23","level":"senior","profession":"consultant","title":"Make the abstract risk personal","scenario":"You're warning the audit committee about a cyber-exposure they treat as theoretical. Persuasion means making the risk personal and concrete: a specific scenario, a specific Monday morning. Bring it to life.","task":"Write a 2-3 sentence scenario that makes the abstract risk feel imminent and real.","tips":["Walk them through a concrete Monday-morning scenario, not a risk category.","Personal and specific beats statistical and abstract for driving action.","Ground it in their actual systems so it can't be dismissed as hypothetical."],"focus":["impact","precision"]},
    {"id":"narrative-con-senior-24","level":"senior","profession":"consultant","title":"The vision that survives the spreadsheet","scenario":"Your strategy has an inspiring vision and rigorous numbers, but in your draft they're in separate sections and the vision feels disconnected from the math. Weave them so the vision is credible and the numbers are meaningful.","task":"Write a 2-3 sentence passage that fuses the aspirational vision with the hard numbers.","tips":["A vision without numbers is a dream; numbers without vision are a spreadsheet.","Attach the aspiration to the specific figure that proves it's reachable.","The fusion is what makes executives both believe and act."],"focus":["impact","precision"]},
    {"id":"narrative-con-senior-25","level":"senior","profession":"consultant","title":"The persuasive one-liner the CEO repeats","scenario":"Your whole strategy needs a single memorable line the CEO can carry into every meeting and repeat to the organization. Your current framing is a paragraph. Distill the persuasive core into one line that spreads.","task":"Write the one-sentence framing of the strategy that the CEO could repeat verbatim.","tips":["The line must be true, memorable, and directional — a compass, not a slogan.","If the CEO can't repeat it from memory, it won't spread.","Test it: does it tell someone what to do differently on Monday?"],"focus":["impact","concision"],"placeholder":"We win by being the fastest, not the biggest — every decision optimizes for speed to the customer."}
  ],
  "delivering-hard-messages": [
    {"id":"hard-con-senior-01","level":"senior","profession":"consultant","title":"Tell the CEO his strategy is failing","scenario":"Your analysis shows the CEO's flagship strategy — the one he staked his tenure on — is not working. You're meeting him one-on-one. Clear is kind: front-load the message rather than burying it in caveats.","task":"Write the 2-3 sentences that deliver the hard message directly and respectfully.","tips":["Lead with the message; a CEO can tell when you're circling.","Respect shows in the evidence and the tone, not in softening the truth.","Burying it wastes his time and reads as cowardice when he finds it."],"focus":["clarity","impact"],"placeholder":"I have to be straight with you: the data says the platform strategy isn't working, and continuing as-is will cost another year and $30M. Here's what I see."},
    {"id":"hard-con-senior-02","level":"senior","profession":"consultant","title":"The clean 'no' to the sponsor's pet idea","scenario":"The sponsor is attached to an initiative your analysis shows is a bad idea. She keeps asking you to find a way to make it work. You need to say no clearly, once, without endless hedging. Deliver the clean no.","task":"Write a 2-3 sentence clean 'no' with the reason and an alternative.","tips":["A clean 'no' respects her more than a slow, hedged one.","One clear reason, not five — and then the door to what would work.","Repeated soft 'maybes' are crueler than one honest 'no.'"],"focus":["clarity","impact"],"placeholder":"No — I can't make that initiative work, and I'd be doing you a disservice to pretend otherwise. Here's the reason, and here's what I'd back instead."},
    {"id":"hard-con-senior-03","level":"senior","profession":"consultant","title":"Behavior, impact, ask — to your engagement manager","scenario":"Your engagement manager keeps overpromising to the client and then scrambling, which is straining the team and the relationship. You need to give feedback using behavior, then impact, then a clear ask.","task":"Write the feedback in three sentences: the specific behavior, its impact, the ask.","tips":["Name the behavior concretely, not a character trait.","Connect it to a real impact on the team and the client.","End with a specific, doable ask — not a vague 'be better.'"],"focus":["clarity","structure"],"placeholder":"In the last two steering committees you committed us to dates the team can't hit. The impact is a scramble every week and eroding client trust. Going forward, run any new commitment past me before you make it."},
    {"id":"hard-con-senior-04","level":"senior","profession":"consultant","title":"Deliver the recommendation to fire an executive","scenario":"Your org review concludes that a specific division head should be replaced. You must deliver this to the CEO, who is close to that executive. Clear is kind: state the conclusion, then the evidence, without euphemism.","task":"Write the 2-3 sentences that deliver the recommendation to replace the executive.","tips":["Euphemism ('leadership challenges') forces the CEO to decode what you mean — be direct.","State it as your recommendation with the evidence, respectfully and unmistakably.","Softening a people recommendation into vagueness helps no one and risks the wrong read."],"focus":["clarity","impact"]},
    {"id":"hard-con-senior-05","level":"senior","profession":"consultant","title":"Tell the client the deal is a mistake","scenario":"The client is excited about an acquisition your diligence says will destroy value. They want your endorsement. You must tell them, clearly, that you recommend walking away — front-loaded, before the reasoning.","task":"Write the 2-3 sentence hard message recommending against the deal.","tips":["Lead with 'I recommend against this deal' — don't make them wait for it.","The reasons follow the recommendation, not the other way around.","This is the moment you earn your fee; don't flinch."],"focus":["clarity","impact"],"placeholder":"My recommendation is to walk away from this deal. I know that's not what you were hoping to hear — here are the three reasons the numbers don't support it."},
    {"id":"hard-con-senior-06","level":"senior","profession":"consultant","title":"Own the engagement's slip to the sponsor","scenario":"Your team missed a milestone and the readout will slip two weeks. You must tell the sponsor. Clear is kind: lead with the slip and the fix, don't bury it under context or excuses.","task":"Write the 2-3 sentences that deliver the slip, own it, and state the fix.","tips":["Lead with the slip and the new date — that's what she needs.","Own it cleanly; excuses read as deflection.","Pair the bad news with the concrete recovery step."],"focus":["clarity","impact"],"placeholder":"The readout slips two weeks, to the 28th — that's on us. Here's what caused it and exactly how we're recovering the time."},
    {"id":"hard-con-senior-07","level":"senior","profession":"consultant","title":"The hard message to your senior partner","scenario":"You've concluded the account is unprofitable and the firm should not renew, but your senior partner is proud of the client logo. You must tell him the relationship should end, clearly, upward. Deliver it.","task":"Write the 2-3 sentences that recommend ending the client relationship to your partner.","tips":["Deliver hard messages upward with the same clarity you'd want from a junior.","Lead with the recommendation and the number that drives it.","Acknowledge the logo's value, then explain why it doesn't cover the cost."],"focus":["clarity","impact"]},
    {"id":"hard-con-senior-08","level":"senior","profession":"consultant","title":"Decline the promotion case","scenario":"A consultant on your team expects your support for promotion, but they're not ready. You must tell them no, clearly and kindly, with a concrete path. Don't leave them with false hope.","task":"Write the 2-3 sentences delivering the 'not this cycle' with the specific gap and path.","tips":["Say 'not this cycle' plainly — vagueness breeds resentment later.","Name the specific gap, not a general 'keep developing.'","Give a concrete path so the 'no' comes with a 'here's how.'"],"focus":["clarity","structure"],"placeholder":"I'm not going to put you forward this cycle, and I want to be clear why. The gap is client-facing leadership — you've delivered analytically, but you haven't yet run a workstream in front of the CFO. Here's how we close that in the next six months."},
    {"id":"hard-con-senior-09","level":"senior","profession":"consultant","title":"Tell the board the timeline is unrealistic","scenario":"The board wants the transformation done in twelve months. Your honest assessment is eighteen minimum. Telling them what they want to hear now guarantees failure later. Deliver the hard timeline truth.","task":"Write the 2-3 sentences that tell the board the timeline is unrealistic, with the honest number.","tips":["Front-load the real number; a comfortable lie now is a broken promise later.","Explain what drives the eighteen months so it's credible, not just cautious.","Boards respect the consultant who protects them from their own optimism."],"focus":["clarity","precision"]},
    {"id":"hard-con-senior-10","level":"senior","profession":"consultant","title":"The behavior feedback to a peer partner","scenario":"A peer partner has been undercutting your engagement in front of the shared client, and it's damaging the work. You need to raise it with them directly, using behavior-impact-ask, not accumulated resentment.","task":"Write the 3-4 sentence feedback to your peer: specific behavior, impact, ask.","tips":["Keep it to the specific behavior and its effect, not their character.","Name the impact on the client and the work, concretely.","End with the specific change you're asking for — and a genuine question."],"focus":["clarity","structure"]},
    {"id":"hard-con-senior-11","level":"senior","profession":"consultant","title":"Tell the sponsor she's the bottleneck","scenario":"The engagement is stalling because the sponsor herself won't make a decision the work depends on. You must tell her, tactfully but clearly, that she's the blocker. Clear is kind, even upward.","task":"Write the 2-3 sentences that tell the sponsor she's the bottleneck, respectfully.","tips":["Name the specific decision that's pending, not a vague 'you're slow.'","Frame it around the cost to her goal, not blame.","Then make it easy: here's the decision, here's what I recommend, here's the deadline."],"focus":["clarity","audience"],"placeholder":"There's one thing holding the whole workstream: the go/no-go on the pilot, which has been with you for nine days. Every day it waits pushes your board date — here's my recommendation so you can decide today."},
    {"id":"hard-con-senior-12","level":"senior","profession":"consultant","title":"The unwelcome pricing finding","scenario":"You must tell the sales leadership their pricing discipline is the problem — their teams give away margin. This lands as an attack on their people. Deliver it clearly while keeping the door open to fixing it together.","task":"Write the 2-3 sentences that deliver the hard finding without making it a personal indictment.","tips":["Attack the practice, not the people who inherited it.","Front-load the finding with the number; don't ease around it.","Immediately signal partnership on the fix so it's not just a verdict."],"focus":["clarity","audience"]},
    {"id":"hard-con-senior-13","level":"senior","profession":"consultant","title":"Tell the client you can't hit the fee they want","scenario":"Procurement wants the work done for half its real cost. You must tell them clearly that you won't do it at that price, without hedging or leaving false hope. Deliver the clean no on price.","task":"Write the 2-3 sentences declining the price, clearly, with what's actually possible.","tips":["Say plainly you can't do it at that number — don't dangle a maybe.","Explain what the price would buy versus what they need.","Offer the honest alternative: reduced scope at their budget, or the real fee."],"focus":["clarity","impact"],"placeholder":"I can't do this engagement at that fee — at half the budget you'd get half the team and a result that won't move your number. Here's what your budget can honestly buy, and what the full outcome actually costs."},
    {"id":"hard-con-senior-14","level":"senior","profession":"consultant","title":"Deliver the failed-pilot verdict to its champion","scenario":"The automation pilot championed personally by an executive isn't working. You must tell him it should stop. Clear is kind: lead with the recommendation, protect his dignity in the framing, not by hiding the verdict.","task":"Write the 2-3 sentences delivering the 'stop the pilot' verdict to its champion.","tips":["Lead with the recommendation; don't make him wait through a defense of the effort.","Protect his standing with the framing ('the pilot did its job'), not by softening the verdict.","Clarity plus dignity — both, not one at the cost of the other."],"focus":["clarity","audience"],"placeholder":"My recommendation is to stop the pilot. It did exactly what a pilot should — it told us this won't scale before you bet the budget on it. Here's the evidence, and here's where I'd put that budget instead."},
    {"id":"hard-con-senior-15","level":"senior","profession":"consultant","title":"Tell your team the engagement is being cut","scenario":"The client cut the engagement short and two people on your team will roll off early. You must tell them clearly and honestly, without false cheer, and with what you're doing for them next.","task":"Write the 3-4 sentences delivering the news to the affected team members.","tips":["Deliver it straight — people sense spin and it makes it worse.","Be honest about what happened without oversharing the client politics.","Move quickly to what's next for them; that's the kindness that matters."],"focus":["clarity","audience"]},
    {"id":"hard-con-senior-16","level":"senior","profession":"consultant","title":"The 'your data is unusable' message","scenario":"The client's data is so poor your analysis is stalled, and it's their fault, not yours. You must tell the sponsor clearly that the data quality is the blocker, without it sounding like blame-shifting.","task":"Write the 2-3 sentences that deliver the data-quality problem clearly and constructively.","tips":["State the problem factually — the data can't support the analysis as-is.","Avoid the blame frame; focus on what's needed to proceed.","Pair it with a specific ask so it's a path, not an accusation."],"focus":["clarity","precision"]},
    {"id":"hard-con-senior-17","level":"senior","profession":"consultant","title":"Correct your own team member in front of the client","scenario":"In a client meeting, your analyst states something wrong that the client will act on. You must correct it in the room — clearly enough to fix the record, gently enough to preserve the analyst. Handle it live.","task":"Write the 2-3 sentences that correct the record without diminishing your team member.","tips":["Fix the fact for the client first — that's non-negotiable.","Frame it as a refinement, not a rebuke: 'let me add to that.'","Protect the analyst's standing; you'll debrief privately after."],"focus":["clarity","audience"],"placeholder":"Let me sharpen one thing there, because it matters for your decision: the churn figure is 14%, not 4% — and that changes the priority. Good that we caught it now."},
    {"id":"hard-con-senior-18","level":"senior","profession":"consultant","title":"Tell the CFO the savings won't materialize","scenario":"The savings the CFO already announced to analysts won't fully land — you've concluded the number was too aggressive. You must tell her before the next earnings call. Front-load the hard truth.","task":"Write the 2-3 sentences delivering the shortfall clearly, ahead of the call.","tips":["Lead with the revised number and that she needs it before the call.","Don't cushion — she needs the real figure to manage her exposure.","Immediately offer the recovery options so it's not just bad news."],"focus":["clarity","impact"]},
    {"id":"hard-con-senior-19","level":"senior","profession":"consultant","title":"Decline to endorse a number you don't believe","scenario":"The client wants you to put your firm's name behind a valuation you think is inflated. You must refuse to endorse it, clearly, because your credibility is the asset. Deliver the refusal.","task":"Write the 2-3 sentences declining to endorse the number, with your honest range.","tips":["Refuse plainly — endorsing a number you don't believe is a one-time credibility spend.","Give your real range so the refusal is constructive, not just a block.","Frame it as protecting them too: an inflated number they act on hurts them."],"focus":["clarity","impact"]},
    {"id":"hard-con-senior-20","level":"senior","profession":"consultant","title":"Tell the founder his successor isn't ready","scenario":"The founder wants to hand the company to his son, but your succession assessment says the son isn't ready to lead. You must deliver this to the founder — the hardest possible message — clearly and with care.","task":"Write the 2-3 sentences delivering the succession finding to the founder.","tips":["This requires maximum care and equal clarity — don't let care erase the message.","State the specific readiness gap, not a judgment of the son as a person.","Offer the path: what would make the son ready, and by when."],"focus":["clarity","audience"]},
    {"id":"hard-con-senior-21","level":"senior","profession":"consultant","title":"The clean no to a scope creep demand","scenario":"The sponsor is pushing a fourth 'quick add' that's really a new workstream, and you've been too soft in declining. You need one clean no that holds the boundary, with the legitimate path. End the pattern.","task":"Write the 2-3 sentence clean 'no' that holds the scope line and offers the real path.","tips":["A firm no now prevents five more soft ones later.","Name the boundary and the reason: it protects her deliverable.","Offer the legitimate route — phase two or a change order — clearly."],"focus":["clarity","impact"],"placeholder":"I have to say no to adding this to the current scope — it's a real workstream, and folding it in silently would put your board date at risk. If it matters, let's scope it properly as a phase two."},
    {"id":"hard-con-senior-22","level":"senior","profession":"consultant","title":"Feedback to a partner who lost the client's trust","scenario":"A junior partner's handling of a sensitive issue damaged the client relationship. You must give them direct feedback — behavior, impact, ask — without it becoming a career threat conversation. Deliver it cleanly.","task":"Write the 3-4 sentence feedback: the specific behavior, its impact on the client, and the ask.","tips":["Anchor to the specific incident, not a pattern accusation.","Name the concrete relationship impact so the stakes are clear.","Make the ask forward-looking and doable, and offer to help."],"focus":["clarity","structure"]},
    {"id":"hard-con-senior-23","level":"senior","profession":"consultant","title":"Tell the board their own governance failed","scenario":"Your review concludes the crisis happened partly because the board itself wasn't asking the right questions. You must deliver this to the board — the people who hired you — clearly and without flattery.","task":"Write the 2-3 sentences that deliver the governance finding to the board respectfully but plainly.","tips":["Telling the board about its own failure is the ultimate hard message — don't dodge it.","Frame it as a system gap the board can fix, not a personal indictment.","Front-load the finding; the recommendation to fix it follows."],"focus":["clarity","impact"]},
    {"id":"hard-con-senior-24","level":"senior","profession":"consultant","title":"Admit your firm's error to the client","scenario":"Your team made a real analytical error that the client relied on. You must tell the sponsor, own it, and lay out the fix — before they discover it. Clear is kind, especially about your own mistakes.","task":"Write the 2-3 sentences owning the error to the client and stating the fix.","tips":["Own it fully and first — 'we made a mistake' before any explanation.","Say exactly what's affected and what isn't.","Lead the remediation; owning it well can preserve the relationship."],"focus":["clarity","impact"],"placeholder":"I need to tell you about an error on our side before you hear it elsewhere: our Q2 figure was overstated by $4M. Here's exactly what it affects, what it doesn't, and how we're correcting it by Friday at no cost to you."},
    {"id":"hard-con-senior-25","level":"senior","profession":"consultant","title":"The hardest recommendation: recommend against your own renewal","scenario":"You've concluded the client doesn't need another phase of consulting — they need to execute what they have. Recommending against your own follow-on work is the hardest message of all, and the most trust-building. Deliver it.","task":"Write the 2-3 sentences recommending the client not renew, and why that's the right call.","tips":["Recommending against your own fee is the strongest trust signal you can send.","Be clear it's genuine: they're ready to execute, more advice would be waste.","Leave the door open for a real future need, honestly framed."],"focus":["clarity","impact"],"placeholder":"My honest recommendation is that you don't need us for a phase two — you need to execute what we built, and hiring us to watch you do it would waste your money. Call me in a year if the market shifts; until then, go run."}
  ],
  "putting-it-together": [
    {"id":"together-con-senior-01","level":"senior","profession":"consultant","title":"The board readout under time pressure","scenario":"You have ten minutes at the board, a forty-slide deck, and a recommendation that costs the sponsor politically. You must lead with the point, own the recommendation, and deliver the hard part with care — all in ten minutes.","task":"Write the opening 3-4 sentences that integrate lead-with-the-point, presence, and a hard message.","tips":["Lead with the recommendation, own it, and front-load the difficult truth — all at once.","Ten minutes means the deck is backup; you speak the argument.","Match the register to a board: assertive, evidenced, unhurried."],"focus":["structure","impact"]},
    {"id":"together-con-senior-02","level":"senior","profession":"consultant","title":"The email that has to do everything","scenario":"You're emailing the CEO to deliver a hard finding, recommend a course, ask for a decision by Friday, and preserve a fragile relationship — in one message she'll read on her phone. Integrate it all, tightly.","task":"Write the full email (5-6 sentences) that lands the finding, recommendation, ask, and tone.","tips":["Lead with the finding and recommendation; put the ask in its own line.","Concision for the phone; every sentence earns its place.","The relationship lives in the tone, not in added length."],"focus":["clarity","concision"]},
    {"id":"together-con-senior-03","level":"senior","profession":"consultant","title":"Match the register: chair vs. analyst","scenario":"You're writing the same core message — the engagement found a major risk — to the board chair and to your own analyst. The content is the same; the register, altitude, and framing must differ entirely.","task":"Write the one-sentence version for the chair and the one-sentence version for the analyst.","tips":["The chair needs the fiduciary altitude; the analyst needs the working detail.","Same fact, different so-what and different vocabulary.","Register is audience calibration made concrete."],"focus":["audience","clarity"]},
    {"id":"together-con-senior-04","level":"senior","profession":"consultant","title":"Rescue the troubled engagement in one message","scenario":"You're taking over a failing engagement and your first message to the frustrated sponsor must acknowledge the past, lead with what changes, structure the recovery, and project presence — all without groveling.","task":"Write the 4-5 sentence takeover message that integrates all of it.","tips":["Lead with what changes today; acknowledge the past in one clause.","Structure the recovery so it reads as a plan, not a promise.","Presence, not apology, is what rebuilds the sponsor's confidence."],"focus":["structure","impact"],"placeholder":"Here's what changes as of today. I've heard the frustration, and it's fair — so the plan, the cadence, and the first deliverable are all different now:"},
    {"id":"together-con-senior-05","level":"senior","profession":"consultant","title":"The one-pager that survives every reader","scenario":"Your one-page recommendation goes to the CEO, CFO, and general counsel — three altitudes, three concerns. It must lead with the point, be airtight on evidence, and speak to each reader without becoming mush. Write the top.","task":"Write the one-pager's opening 3-4 sentences that hold for all three readers.","tips":["Anchor on the CEO's decision, but make the evidence CFO-proof and the risk GC-aware.","One primary reader for the frame; serve the others inside the argument.","Precision and structure do the work of speaking to three people at once."],"focus":["audience","precision"]},
    {"id":"together-con-senior-06","level":"senior","profession":"consultant","title":"Answer a hostile board question completely","scenario":"A director attacks your central recommendation as reckless. You must answer the actual question, hold your position with presence, bring specific evidence, and do it in under a minute. Integrate pressure, presence, and precision.","task":"Write the 3-4 sentence response that answers, holds, and evidences under fire.","tips":["Answer the literal challenge first, calmly, then support with one specific.","Hold the position without defensiveness — presence is the frame.","One precise piece of evidence beats a paragraph of justification."],"focus":["impact","precision"]},
    {"id":"together-con-senior-07","level":"senior","profession":"consultant","title":"The proposal opening that wins the work","scenario":"Your proposal's first paragraph must show you understand the client's problem better than they've stated it, frame the change, lead with your approach, and set up the fee — all before they lose interest. Integrate narrative and structure.","task":"Write the 4-5 sentence proposal opening that does all of it.","tips":["Open inside their problem, stated sharply — that's the narrative hook.","Then lead with your approach and the outcome, not your credentials.","Structure it so procurement and the sponsor both find their thread."],"focus":["audience","impact"]},
    {"id":"together-con-senior-08","level":"senior","profession":"consultant","title":"The steering committee that pivots the engagement","scenario":"You must tell the steering committee the original hypothesis was wrong, reframe the work, keep their confidence, and get approval to pivot — in one readout. Integrate hard message, narrative, and driving to a decision.","task":"Write the 4-5 sentence opening that delivers the pivot and drives to approval.","tips":["Frame the pivot with SCQA so it feels earned, not like failure.","Own the new direction with presence; a tentative pivot loses the room.","End by asking for the specific approval you need."],"focus":["structure","impact"]},
    {"id":"together-con-senior-09","level":"senior","profession":"consultant","title":"Edit your own deck like a reader","scenario":"Your final deck is done and you have thirty minutes to edit it as a skeptical CEO would read it, not as the author who loves every slide. Find what to cut, what to sharpen, what buries the point. Do the reader's pass.","task":"Write the three edits you'd make, each naming the slide problem and the fix.","tips":["Read as the CEO: which slides change her decision, which just inform?","Look for buried recommendations and question-titles to sharpen.","Cutting a good slide you love is the hardest, most valuable edit."],"focus":["concision","clarity"]},
    {"id":"together-con-senior-10","level":"senior","profession":"consultant","title":"The fee negotiation, fully staged","scenario":"You're going into a fee negotiation with procurement pushing for a 15% cut. You must anchor on value, hold price with presence, offer a real alternative, and keep the relationship — all in a two-minute exchange. Integrate it.","task":"Write the 3-4 sentence opening move that anchors, holds, and keeps the door open.","tips":["Anchor on the outcome's value before any price discussion.","Hold the fee with composure; offer movement on terms, not price.","Keep it warm — you want this client after the deal closes."],"focus":["impact","audience"],"placeholder":"Before we talk price, let's be clear on what this is worth: a $40M outcome for a team that's done it four times. I'm holding the fee — but I can move on payment terms and phasing if cash timing is the real issue."},
    {"id":"together-con-senior-11","level":"senior","profession":"consultant","title":"The CEO one-on-one that covers everything","scenario":"You have twenty minutes alone with the CEO to deliver a hard strategic finding, recommend a bold move, pre-empt her objection, and secure her sponsorship — before her next meeting. Integrate the whole toolkit.","task":"Write the 4-5 sentence opening that leads, persuades, pre-empts, and asks.","tips":["Lead with the finding and recommendation in the first two sentences.","Pre-empt her strongest objection before she can voice it.","End with the specific sponsorship you need from her."],"focus":["impact","structure"]},
    {"id":"together-con-senior-12","level":"senior","profession":"consultant","title":"The all-hands that has to land three ways","scenario":"You're presenting the operating-model change to a mixed room of executives, managers, and frontline staff. You must be precise for the executives, concrete for the frontline, and structured enough for all. Integrate audience and structure.","task":"Write the opening 3-4 sentences that hold all three audiences at once.","tips":["Lead with the change in plain terms everyone understands.","Give the executives the why, the frontline the what-changes-Tuesday.","One clear structure carries all three through the same arc."],"focus":["audience","structure"]},
    {"id":"together-con-senior-13","level":"senior","profession":"consultant","title":"The diligence verdict the night before bids","scenario":"The deal partner needs your full verdict tonight: proceed or not, at what price, with what confidence, and what would change your view — in a five-sentence message he'll read on his phone. Integrate precision, structure, and concision.","task":"Write the 5-sentence verdict message that a deal partner can act on immediately.","tips":["Verdict first, price second, confidence third — in that order.","Every claim carries its confidence level; he's pricing your uncertainty.","Concision under deadline is a gift to a partner making a bet."],"focus":["precision","concision"],"placeholder":"Proceed, but at 8-10% below ask. High confidence on the market, moderate on the synergies — here's what separates them:"},
    {"id":"together-con-senior-14","level":"senior","profession":"consultant","title":"The recovery email after a bad meeting","scenario":"A steering committee went badly — the sponsor felt blindsided by a finding. You must write the follow-up that repairs trust, re-establishes the finding clearly, and resets the path forward, without over-apologizing. Integrate hard message and audience.","task":"Write the 4-5 sentence recovery email that repairs, restates, and resets.","tips":["Acknowledge how it landed without retracting the substance.","Restate the finding cleanly so it's on the record, undiluted.","Reset forward: here's how we handle the next conversation better."],"focus":["audience","clarity"]},
    {"id":"together-con-senior-15","level":"senior","profession":"consultant","title":"The partner-meeting update, fully integrated","scenario":"You have four minutes at the partner meeting to report your practice's health honestly — strong revenue, thin pipeline — recommend an action, and ask for help, without spin. Integrate precision, structure, and presence.","task":"Write the 4-5 sentence update that reports honestly, recommends, and asks.","tips":["Lead with both numbers — the strength and the risk — precisely.","Structure it: where we are, the one risk, the ask.","Presence is self-reporting the risk before a peer surfaces it."],"focus":["precision","structure"],"placeholder":"Revenue's up 22%, but pipeline coverage is thin at 1.4x — I want to flag it now, not in Q3 when it bites. Here's what I'm doing about it and where I need the partnership's help:"},
    {"id":"together-con-senior-16","level":"senior","profession":"consultant","title":"The client crisis call","scenario":"A crisis has erupted on the engagement and the CEO calls you at 9pm for your read. You must give a calm, structured account — what happened, what it means, what you recommend — under pressure, in a two-minute call. Integrate presence, structure, and pressure.","task":"Write the 4-5 sentences you'd say to open that call.","tips":["Open with composure and structure: 'Three things — what happened, what it means, what I'd do.'","Give your read plainly; the CEO needs judgment, not just facts.","Calm under a 9pm crisis is the presence that earns the next engagement."],"focus":["structure","impact"]},
    {"id":"together-con-senior-17","level":"senior","profession":"consultant","title":"The unwelcome recommendation to the executive who hired you","scenario":"The COO who hired you must hear that his own function is the problem your study found. You must deliver it clearly, own the recommendation, keep his sponsorship, and give him a dignified role in the fix. Integrate hard message, presence, and persuasion.","task":"Write the 4-5 sentence delivery that lands the finding and keeps him on your side.","tips":["Front-load the finding; then give him a stake in fixing it, not just a verdict.","Own the recommendation with presence — hedging insults his intelligence.","Persuade by making him the leader of the fix, not its subject."],"focus":["impact","audience"]},
    {"id":"together-con-senior-18","level":"senior","profession":"consultant","title":"The strategy the CEO can carry into the boardroom","scenario":"Your strategy must arm the CEO to sell it to her board without you in the room: one clear recommendation, three reasons, a memorable frame, and the pre-empted objection. Integrate narrative, structure, and concision.","task":"Write the 4-5 sentence version the CEO can deliver to her board verbatim.","tips":["Give her the one-line frame she can repeat and the three reasons beneath it.","Pre-empt the board's strongest objection so she's not caught flat.","Concise enough to memorize; structured enough to survive questions."],"focus":["structure","concision"]},
    {"id":"together-con-senior-19","level":"senior","profession":"consultant","title":"The staffing negotiation, both ways at once","scenario":"You must ask the practice leader for two more consultants (internal) and manage the client's expectation about the timeline (external) — two audiences, two registers, one coordinated move. Integrate audience and structure.","task":"Write the internal ask (2 sentences) and the client-facing note (2 sentences), each in the right register.","tips":["Internal: crisp ask, stakes, done. The practice leader triages fast.","Client-facing: reframe around their board date, not your staffing.","Same underlying reality, two deliberately different framings."],"focus":["audience","concision"]},
    {"id":"together-con-senior-20","level":"senior","profession":"consultant","title":"The final readout close that lands everything","scenario":"You're closing a fourteen-week engagement's final board readout. You must restate the governing recommendation, land the ask, acknowledge the hard choices honestly, and drive to a decision — in a clean two-minute close. Integrate structure, presence, and impact.","task":"Write the 4-5 sentence close that restates, asks, and drives to the decision.","tips":["Restate the one governing recommendation the whole engagement built to.","Name the hard choice honestly, then ask for the decision.","The close is what they remember — make it deliberate and confident."],"focus":["structure","impact"],"placeholder":"So it comes down to one recommendation: close Riverside and reinvest in the two growth plants. It's the hard choice — but it's the one that hits your target and funds your future. I'd like your decision today: what stands between you and yes?"},
    {"id":"together-con-senior-21","level":"senior","profession":"consultant","title":"The write-up a skeptical CFO can't poke","scenario":"Your recommendation write-up will be read by a CFO who lives to find the hole. You must lead with the point, make every number traceable, pre-empt her objections, and stay concise. Integrate precision, structure, and persuasion.","task":"Write the opening 4-5 sentences that lead, evidence, and pre-empt for the skeptic.","tips":["Lead with the recommendation, then the traceable number that anchors it.","Pre-empt her top objection inside the argument, with data.","Every claim carries its source; she's checking each one."],"focus":["precision","impact"]},
    {"id":"together-con-senior-22","level":"senior","profession":"consultant","title":"The message that says no and keeps the client","scenario":"You must decline the client's request for out-of-scope work, hold the boundary with presence, offer a real alternative, and leave the relationship stronger — in a warm, brief message. Integrate hard message, concision, and audience.","task":"Write the 3-4 sentence message that declines, holds, offers, and warms.","tips":["Clean no with the honest reason; don't dangle a false maybe.","Frame the boundary around their interest, not the contract.","Warmth in the tone and a real alternative keep the client close."],"focus":["clarity","audience"]},
    {"id":"together-con-senior-23","level":"senior","profession":"consultant","title":"The verbal update that has to be perfect","scenario":"The CEO stops you in the hall and gives you sixty seconds to update her on the whole engagement before her next meeting. You must lead with the headline, structure three points, and land the one decision she needs to make. Integrate everything, spoken.","task":"Script the 60-second verbal update — lead, structure, and the ask.","tips":["Headline first; she may only get thirty seconds of the sixty.","Three points, signposted, so she can follow at a walk.","End with the one decision — make the hallway moment count."],"focus":["structure","concision"],"placeholder":"Headline: we can hit your target, but it takes closing one plant. Three quick things — the finding, the plan, and one decision I need from you by Friday:"},
    {"id":"together-con-senior-24","level":"senior","profession":"consultant","title":"The proposal that competes on more than price","scenario":"You're the more expensive bid and procurement will compare you to two cheaper firms in a table. Your proposal must justify the premium through outcome, precision, and a narrative of their success — while giving procurement clean rows. Integrate audience, precision, and persuasion.","task":"Write the 4-5 sentence section that justifies the premium to both the sponsor and procurement.","tips":["Make the outcome so specific the premium reads as cheap insurance.","Give procurement clean, comparable rows so they can score you fairly.","The narrative wins the sponsor; the precision protects you in the table."],"focus":["audience","precision"]},
    {"id":"together-con-senior-25","level":"senior","profession":"consultant","title":"The capstone: the whole engagement in one page","scenario":"Everything comes together: a single page to the board that carries fourteen weeks of work — the governing recommendation, the evidence, the hard choice, the decision needed — leading with the point, precise, persuasive, and concise enough that the chairman reads all of it. Integrate every skill.","task":"Write the full one-page top (6-7 sentences): recommendation, three reasons with evidence, the hard truth, and the decision asked for.","tips":["Recommendation in sentence one; the chairman should know your view immediately.","Three reasons, each with a traceable number, each pre-empting a doubt.","Name the hard choice honestly and end by asking for the specific decision."],"focus":["structure","impact"],"placeholder":"Recommendation: close the Riverside plant this year and reinvest the $40M into the two growth plants. Three reasons drive it, each independently sufficient:"}
  ],
};
